INSERT INTO `abstrata` (`key`, `title`, `text`) VALUES
('audiokind', 'AUDIOKIND', 'Your weapon makes noises as you swing it, and even louder ones when you connect! Your strife specibus gains **[Sonic]** **[Energy]** damage. On a **MAX** **[Strife]** roll, you can reduce damage by **1** and **[Deafen]** all opponents for **3 turns**.'),
('autokind', 'AUTOKIND', 'Can\'t strife for shit? Don\'t worry, this weapon strifes for you! Not well, but it does it! You automatically get a **GOOD** on every **[Strife]** roll using this weapon, but no higher, even with **[Tier Up]** or **[Boost]** or similar.'),
('beamkind', 'BEAMKIND', '***[Passive]**\nYour weapon is crackling with energy. Your strife specibus gains **[Laser]** **[Energy]** Damage. On a **MAX** **[Strife]** roll, you do an additional **2 [Laser]** damage to yourself and the target as the beam charges up and explodes violently.\n'),
('burnkind', 'BURNKIND', 'Your weapon is all fiery and shit! Your strife specibus gains **[Blaze]** **[Energy]** Damage. On a **MAX** **[Strife]** roll, you can reduce damage by **1** and set the target **[Ablaze]**.\n'),
('drainkind', 'DRAINKIND', 'Your weapon drains the target’s power! You always deal **1** less damage (min. 0) with this weapon, but give the target **1**/**2**/**3** **[Drag]** and gain **1**/**2**/**3** **[Boost]** on a **GOOD**/**GREAT**/**MAX** **[Strife]** roll.\n'),
('ectoplasmkind', 'ECTOPLASMKIND', 'Fuck ghosts! Your strife specibus gains **[Freaky]** **[Energy]** Damage. On a **MAX** **[Strife]** roll, you can reduce damage by **1** and make the target **[Terrified]**.'),
('focuskind', 'FOCUSKIND', 'Like a bent spoon, or something! This weapon serves as a focus for your **[Psionic]** powers, and you can spend an action focusing on it to make your next **[Psionic]** or **[Magic]** **[Strife]** roll **[Tier Up]**; focusing gives you **2 [Drag]**.'),
('icekind', 'ICEKIND', 'Brrr… your weapon is coated in frost. Your strife specibus gains **[Frost]** **[Energy]** Damage. On a **MAX** **[Strife]** roll, you can reduce damage by **1** and **[Slow]** the target for **2 turns**.'),
('jpegkind', 'JPEGKIND', 'Sord… your weapon is weird and artifacts. Your strife specibus gains **[Glitchy]** **[Energy]** damage. On a **MAX** **[Strife]** roll, you trigger a **REALITY CRACK Hazard**, and your target\'s rolls against it are **[Inept]**.'),
('massivekind', 'MASSIVEKIND', 'Holy FUCK that\'s a big weapon. Like, that sword is the size of a tree! That cannon is HUGE! You do **+1** damage on all attacks, but **[Strife]** rolls are **[Lengthy]**.'),
('meltkind', 'MELTKIND', 'Your weapon is dripping with corrosive liquids! Your strife specibus gains **[Acid]** **[Energy]** damage. On a **MAX** **[Strife]** roll, you can reduce damage by **1** and destroy an item in the target\'s sylladex.'),
('mercykind', 'MERCYKIND', 'Your weapon does not kill, merely knocks you out. All damage you deal is **[Non-Lethal]**. The blunted nature of your weapon additionally makes it safer to wield - your **BAD** **[Strife]** rolls **[Tier Up]** to **OK**.'),
('mickind', 'MICKIND', 'C\'mon, drop your weapons, face me! With this weapon(?) you can make a **REQUEST** to engage in **[Verbal]** combat rather than **[Physical]**, ending the current combat encounter and starting one that uses **WORDPLAY** instead.'),
('mobilekind', 'MOBILEKIND', 'Cool laser skates, sharp-edged hoverboards, rocket jetpacks… this weapon is also a vehicle! Your item is a **TINY 1 HORSEPOWER** Vehicle that uses your **[Strife]** stat to **VEHICULATE**. You can upgrade it like a regular Vehicle if you choose.'),
('openkind', 'OPENKIND', 'Your weap— oh! This isn\'t a weapon at all! You\'ve just got your hands, horns or some other bodily weapon. Pretty cool! You have an additional **2 VP**, since your hands aren\'t full.'),
('poisonkind', 'POISONKIND', 'Your weapon is coated in debilitating poison. On a **GREAT** **[Strife]** roll you can do one less damage and instead apply the **[Poisoned]** condition on a **[Recharge: 3]**.'),
('rangedkind', 'RANGEDKIND', 'Your weapon can shoot projectiles. Pew pew pew! It can hit **[Flying]** targets without any problem.'),
('sharpkind', 'SHARPKIND', 'Haha, you\'ll meet your end n— owch! Ngh! That hurt! This extremely sharp weapon **[Tiers Up]** all **GOOD** **[Strife]** rolls to a **GREAT**, and all **OK** **[Strife]** rolls to a **BAD**. '),
('shieldkind', 'SHIELDKIND', 'Your weapon is designed to block damage, not deal it. Every turn which you don’t manage to deal damage, you gain **1** **[Resistance]** against the next **[Somatic]** damage you take as you prepare for the counterattack.'),
('stickykind', 'STICKYKIND', 'Blech! Your weapon is all… gummy! Is this slime? Targets struck by this weapon have a **-2** **[Nerf]** to **ABSCOND** rolls for a turn.'),
('sturdykind', 'STURDYKIND', 'Your weapon is well made and hard to break. While wielding it, you gain **+1 HP**.'),
('voltkind', 'VOLTKIND', 'ZAP! You arc electricity into your target. Your strife specibus gains **[Electric]** **[Energy]** Damage. On a **MAX** **[Strife]** roll, you can reduce damage by **1** and give the target **[Sensory Overload]**.');
INSERT INTO `affliction` (`key`, `title`, `tags`, `text`) VALUES
('calamitypox', 'CALAMITYPOX', '[Affliction][Slowburn][Magic] \r\n', 'You caught the Calamitypox, a wild affliction caused by a meta breaking virus that infects trolls that makes trolls go buckwild with redefining themselves and blurring the lines of reality. At the start of every encounter, roll 1d12 to determine a caste (with 12 being Kids, not Fuchsia). Then, roll 1d8 to determine what tree in said caste you take. On a roll from 6-8, you reroll for a tree (as you’re overcome with indecision). As this is a magical affliction, you can even take trees that are normally unavailable. This includes **[Psionic]** trees, since these effects are not real and are just the reality-breaking pox creating figments). Your **[Psionic]** and **[Magic]** rolls are **[Inept]** by default, because no amount of Calamitypox virus could make up for the sheer amount of time it takes someone to hone their magical or psionic skills.\r\n\r\n> **STAGE 0**: You failed your GREAT **+IMG** roll and have succumbed to the pox! ACHOO! You replace your current tree’s **[Basic]** moves with the moves of the rolled tree. Every time you roll an OK or lower, you become **[Stressed]**.\r\n\r\n> **STAGE 1**: It’s really not what you want… but this is your new destiny! The pox is starting to warp the way you view yourself even more. You now gain the **[Advanced]** moves of your new tree, and start every encounter **[Clumsy]**.\r\n\r\n> **STAGE 2**: You tried Summoner and got rabies, and living as a Nyanarchist gave you frostbite. Seeing people actually succeed with what they’re doing almost makes you burst a blood vessel in frustration. Whenever your opponent uses a caste move, you gain **2 [Drag]**.\r\n\r\n> **STAGE 3**: The Calamitypox has progressed so far, any original attachment to your previous tree is severed. You now have the **[Ultra]** of your new tree. This repeats indefinitely until you\'re cured by a docterror. \r\n'),
('carcinization', 'CARCINIZATION', '[Affliction][Slowburn]\r\n', 'Evolution may take many long and circuitous routes, but it always ends in one thing... becoming a crab. At least for you. You pissed off Gl\'bgolyb or one of her ardent followers, and now you\'re gonna pay the price. With your trollmanity. Deep-sea violets are immune to this **[Affliction]**. Roll **+IMG** to resist being forcibly evolved into a crab.\r\n\r\n> **STAGE 0**: You\'re feeling a little crabby, but no dark magic is reeeeeallly taking hold of you. Right? Right? Your urge to walk sideways and snap your hands together like they\'re crab claws is just a fun little habit you\'ve picked up. You take a **-1 [Nerf]** to all **+PSP** rolls as you\'re consumed with thoughts of scuttling around on the ocean floor.\r\n\r\n> **STAGE 1**: Your joints feel stiff.. your skin is sturdier, somehow, even if moving around is a little harder than it used to be. Your **+PSP** and **+GRA** rolls both take a **-2 [Nerf]**, although your **+APP** rolls take a **+1 [Buff]** as you\'re becoming somewhat of a walking tank.\r\n\r\n> **STAGE 2**: Oh, you\'re really in it now. \'It\' being the mosh pit of the crab rave. Your skin- chitin?- is hard to the touch now, and you can\'t walk any way but sideways. No matter how hard you try. Your **+PSP** and **+GRA** rolls **[Tier Down]** now, although you\'ve gained an additional **two points of HP** on top of your **+1 [Buff]** to **+APP**. People are probably starting to look at you weirdly. \r\n\r\n> **STAGE 3**: Crab noises. You\'re visibly crabby now- whether that means stalks for eyes, serrated fingernails, or having a bunch of useless stubby extra legs is up to you or your clouder. In addition to the previous effects, you now gain the **[Cullbait]** tag. Rolls to throw off this affliction are now **[Inept]** since you literally have to molt your entire crabby exoskeleton to get back to normal- succeeding this roll, though, will immediately cure the affliction as you shed your crabmanity and become a troll once more.\r\n\r\n> **STAGE 4**: You\'ve done it... you\'ve achieved full crabdom. You\'ve evolved into a crab and there\'s no going back now, for better or worse. All previous effects disappear as you get used to your crabby body, although you still have the **[Cullbait]** tag. All stats except **+APP** and **+GRT** lower by **-1**, although **+APP** and **+GRT** get a **+2**, even driving you up to +5. You also have big meaty claws. You get the RAZORKIND NATURAL WEAPONS **[Mutation]** for free.\r\n'),
('choking', 'CHOKING', '[Affliction][Rapid]\r\n', 'Oh god… what’s that in your throat? Sand? Smoke? A big ol’ bag of dicks? Whatever it is, it’s making it hard to breathe! Pweh, pweh, get it outta there!\r\n\r\n> **STAGE 0**: You failed your GOOD +GRT roll against whatever it is that’s in your throat! Blegh! Pweh pweh! Ptooey! Your **[Manipulate]** rolls are **[Inept]** for a turn! If the source of this affliction was **[Magic]** or **[Psionic]**, you need to roll **+IMG** instead.\r\n\r\n> **STAGE 1**: Bweeeegh! You can’t speak! Help, help! You can’t make any **[Manipulate]** rolls, and all you can do is say stuff like “NGHK-” or “GAH-” or stuff. \r\n\r\n> **STAGE 2**: Oh golly jeez, you’re getting dizzy! You become **[Tired]**.\r\n\r\n> **STAGE 3**: Whoawhoawhoa, you’re **[Exhausted]**, everything’s going dark…\r\n\r\n> **STAGE 4**: Aaaaand lights out. Turns out, you need air to breathe! You are **[Unconscious]**.'),
('dancingFever', 'DANCING FEVER', '[Affliction][Rapid]\r\n', 'You listened to a pretty rocking band and now your feet are moving on their own. You might have two left feet, but for once you don\'t care. Or maybe you just have Dancing Fever? Uh oh.\r\n\r\n> **STAGE 0**: There\'s a musical sound in the back of your head, pushing you... to dance. If you don\'t pass a **GREAT +IMG** check, you\'ll fall victim to the fever.\r\n\r\n> **STAGE 1**: You failed your **+IMG** check and now it\'s boogiewoogie time. You gain a **+1** to **GRA** rolls, but a **-1 [Nerf]** to anything else if you do not take an action to roll FRAYMOTIF on any turn. You do not actually gain the effects of FRAYMOTIF unless you had enough **[Buildup]**.\r\n\r\n> **STAGE 2**: Funk town TSA (Troll States of America)! It\'s time to dance! Your dancing is advancing feverishly, and now you can hear the music ever more clearly. Your **[Buff]** to **+GRA** increases to **+2**, but the **[Nerf]** to everything else becomes **-2**. \r\n\r\n> **STAGE 3**: The music... you can hear it. It\'s the fabric of the universe, the magic behind your signs calling to y-- FUCK that get dancing! You no longer need to roll FRAYMOTIF, and instead automatically achieve a **GOOD** result for it if you have not yet done so. If you have, you\'re **[Quickened]** for the encounter! However, you\'re entirely focused on the dance. You\'re **[Inept]** at all **[Physical]** rolls. This stage repeats until you roll a **GREAT +IMG**.\r\n\r\n> **STAGE 4**: Oof... you burnt yourself out dancing. Your Fraymotif ends, and cannot begin again for the rest of the encounter. You remain **[Inept]** at all **[Physical]** rolls as you\'re just so tired. \r\n'),
('doubleMobiusReacharoundVirus', 'DOUBLE MOBIUS REACHAROUND VIRUS', '[Affliction][Slowburn]\r\n', 'You messed with the wrong hacker! Whether it\'s from bullying a computer nerd or discovering some ancient, lost fragments of another canon in some code, you\'ve unwittingly invited a horrible curse upon you. Beware the virus! It may spell your doom!\r\n\r\n> **STAGE 0**: YOUR COMPUTER! NOOOOO! When you first receive this affliction, one piece of **[Tech]** on your person immediately explodes. This happens regardless of whether or not you actually pass your **GREAT +IMG** roll. This sucks!\r\n\r\n> **STAGE 1**: Technology is acting strange around you, and misfortune appears to be following you like a bad smell. It\'s a **[Lengthy]** action to activate any **[Tech]** item as they glitch and buzz. Any time you gain **[Drag]**, you gain 1 more.\r\n\r\n> **STAGE 2**: Everyone around you is slowly affected by your curse! The effects of a STAGE 1 now apply to all trolls in an encounter.\r\n\r\n> **STAGE 3**: Doom has a firm hold of you now. You and everyone you ever know will ultimately die, and it\'ll be your fault. You are always **[Serious]**. Rolls on **[Tech]** items in your presence are **[Tiered Down]**. You gain **1 [Drag]** every turn; you only add **+1 [Drag]** to **[Drag]** gained through other means. Any time you use **[Drag]**, you still keep half of what you used rather than discard all of it.\r\n\r\n> **STAGE 4**: You can\'t even hide your secrets from the machine anymore. Your thoughts will randomly appear on social media; usually while you\'re **[Analyzing]** something. The code is, for some reason, unable to complete its original purpose, so it\'s evidently making a new one. Metal starts to grow from your skin here and there, giving you the **[Bloodied]** condition- your blood color isn’t revealed, but you’re still healblocked!\r\n\r\n> **STAGE 5**: You are a computer. A host to the virus, as it were. You gain the ROBOT Template, and no longer have the DOUBLE MOBIUS REACHAROUND VIRUS.'),
('dropshadowSyndrome', 'DROPSHADOW SYNDROME', '[Affliction][Slowburn][Eerie]\r\n', 'It could be a really bad skin rash. Or it could be your untimely demise crawling through your soul. Who knows! After coming far too close to death, or potentially being brought back from it, you\'ve got a sickly problem with your mortal shell. \r\n\r\n> **STAGE 0**: Itchy itchy itchy… dead skin appears around the point of infection. A bite wound? A murder wound? Your heart? You failed your **GOOD +APP** roll, and you are **[Poisoned]** so long as you have this **[Affliction]**.\r\n\r\n> **STAGE 1**: Your reflexes are dulled… you are **[Stunned]** on the first round of combat.\r\n\r\n> **STAGE 2**: You have… strange resilience, suddenly. You only fall **[Unconscious]** at **-2 HP**, but you are **[Slowed]** once you have **0 HP** or less.\r\n\r\n> **STAGE 3**: Your body is a cage. You are **[Trapped]** at all times as well as the former stages’ effects, as the final days of undeath crawl over you. Hrrrnnnh…\r\n\r\n> **STAGE 4**: Aaaaand you\'re a Shadowdropper. RIP. You lose this **[Affliction]** and gain the Shadowdropper **[Template]**.\r\n'),
('drowning', 'DROWNING', '[Affliction][Rapid]\r\n', 'Glub glub glub! Not all trolls are aquatic. In fact, most aren\'t. Seadwellers often use this to their advantage, dragging trolls to their doom beneath the waves. Hope you paid attention in swimming lessons as a grub! This **[Affliction]** does not affect Violet or Fuchsia trolls.\r\n\r\n> **STAGE 0**: You\'re being pulled under! You still have air in your lungs; a **GOOD +GRT** roll will probably get you to safety quickly! Swim! Swim!\r\n\r\n> **STAGE 1**: Gurgle Gurgle! You\'ve run out of air, and water is starting to seep into your lungs! Come on, swim! So long as you don\'t panic, you\'re fine. You take **1 [Somatic] damage** and **2 [Drag]**.\r\n\r\n> **STAGE 2**: And you\'re panicking. Fuck shit fuck, you don\'t wanna be fish food! You become **[Scared]**. Your rolls now must be **GREAT +APP** rolls. You take **1 [Somatic] damage** and **2 [Drag]**. This stage repeats until you pass a **GREAT +APP** roll, upon which you return to STAGE 1 and must swim. Returning to **[Stage 2]** a second time makes you **[Terrified]**. You either get out of the water… or you drown! Simple. \r\n'),
('eerieAilment', 'EERIE AILMENT', '[Affliction][Slowburn][Magic] \r\n', 'Sometimes, something about somebody makes the evil slide off them. But much like toxic sludge, evil tends to stain! When a character would gain an **[Eerie]** Template such as through an **[Affliction]**, but cannot do so due to already being **[Eerie]**, not being able to become that specific type of **[Eerie]** Template or other similar reasons, they gain this **[Affliction]**. This **[Affliction]** is lost when whatever is attempting to inflict the **[Eerie]** Template is resolved, and it cannot be gained or lost any other way. \r\n\r\n> **STAGE 0**: You failed to cure whatever **[Affliction]** ailed you or have been struck with some kind of curse and have been overwhelmed with the evil flu! Achoo! All **[Eerie]** moves gain a **+1 [Buff]**, but all **[Drag]** gained is increased by 1 as your body begins to ache and complain. This stage repeats indefinitely.'),
('furyFever', 'FURY FEVER', '[Affliction][Rapid]\r\n', 'HRNNNHHH... GGRNNNHHH... GNASH GNASH SNARL. You\'re entering a primal state of pure Trollic fury, as foam spews from your mouth and your teeth sharpen. It\'s quite horrifying! Fury Fever shuts off all intelligent thought and makes you attack and kill at random. It\'s horrible!\n\n> **STAGE 0**: OWCH! YOUR ARM! You failed a **GREAT +APP** roll against whatever exposed you to the **[Affliction]**- usually a bite from a lusus with this [Affliction], or Gog forbid, a troll! You\'re a little dizzy... Your **[Mental]** rolls are all **[Inept]**.\n\n> **STAGE 1**: HRRRHHH... ANGY. Why are you angry? Dunno! But you are! You become **[Enraged]**. Your **[Mental]** rolls are all **[Godawful]**. This cannot be removed by traditional means; only removing the **[Affliction]** stops your rage. It affects you even if you are immune to Emotions.\n\n> **STAGE 2**: RRRRRRAAAAAARRRGH! Oh my god, you\'re going nuts! You wanna BITE BITE GNASH GNASH BITE! You become **[Out Of Control]** and cannot use **[Mental]** rolls at all. You can\'t use your strife specibus- you just BITE! \n\n> **STAGE 5**: AAAAAND you\'re **[Unconscious]**. Phew! That was a lot of energy you just used up, huh? You begin the next encounter with the **[Tired]** condition, and your memories of your fever fueled fury are hazy at best. That was fucked up!'),
('moonbarkMadness', 'MOONBARK MADNESS', '[Affliction][Slowburn][Eerie]\r\n', 'Hmmm. You really hope that weird barkbeast that stood on two legs and bit you wasn\'t something scary. Something… supernatural, as it were. Oh well!\r\n\r\n> **STAGE 0**: You should really not have tried to pet that dog. You failed a **GREAT +APP** roll, and you\'re paying the consequences now. The consequences being… you\'re HUNGRY! Eating any food item is a **[Lengthy]** action as you need to stuff loads into your gabber.\r\n\r\n> **STAGE 1**: That\'s… strange. You woke up in the middle of the woods in shredded clothes. How\'d that happen? You are **[Drowsy]** at the start of your next encounter, as well as the effects of STAGE 0. You are now on a timer; if you don\'t succeed your **GREAT +APP** roll before the next Full Moon in real life (or the one after that, if the next one is less than a week away), you gain the MOONBARK Template.\r\n\r\n> **STAGE 2**: You have not mastered the change; the change is, however, mastering you. You\'re a monster. Whenever you take **4 or more damage** in an encounter, you immediately gain the effects of MOONRAGE MODE from GRR BARK BARK BARK, the MOONBARK Template. Good luck! This stage repeats indefinitely until the next Full Moon irl, as mentioned in STAGE 1.\r\n'),
('haunting', 'HAUNTING', '[Affliction][Slowburn][Eerie]\r\n', 'The dead grip your arms and won\'t let you go far. Alternia is rampant with the ghosts of the unjustly dead, and though Rustbloods are the ones to communicate with them most often, the long dead who have forgotten how to live often take pleasure in fucking up a particular target. \r\n\r\n> **STAGE 0**: You failed to ward off an incoming haunting with a **GREAT +IMG** roll. Nothing much happens for now, but it\'s kinda cold. You take **3 [Drag]** when you gain this affliction.\r\n\r\n> **STAGE 1**: Weird coincidences keep happening, and it\'s starting to unsettle you. It takes an action to pull items from your SYLLADEX, including your STRIFE SPECIBUS- it\'s like they\'re fighting back against you. Any time you receive **[Drag]**, you take an additional **1 [Drag]** as your misfortune doubles.\r\n\r\n> **STAGE 2**: Your paranoia and anxiety is overwhelming. Something\'s here, in this very room, and it’s that damn thing from Stage 0\'s fault! On top of the effects of Stage 1, you\'re also permanently **[Scared]**. Other Emotions that might replace this last for **3 rounds** before returning to **[Scared]**.\r\n\r\n> **STAGE 3**: Stop stacking chairs! Please, you\'re begging them! You know it\'s a funny reference to the Troll Steven Spielberg movie IN WHICH A HIVE\'S INHABITANTS DISCOVER THEIR HOME IS BUILT OVER A CULLPIT AND NOW A POLTERGEIST IS HAUNTING THEM AND THEY MUST CONTACT AN EXORCIST TO GET THEIR YOUNG FRIEND OUT OF THE PHANTOM DIMENSION. Whenever you turn your back on the ghosts, something weird and freaky happens, and you hate it! You are **[Inept]** at all **[Magic]** rolls, and witnessing other trolls use **[Magic] [Terrifies]** you. Whenever you roll a BAD roll of any kind, you gain **2 [Drag]**, and 4 on a MIN as the ghosts visibly start doing spooky shit. Other trolls witnessing this are **[Scared]**. You still gain the effects of Stage 2.\r\n\r\n> **STAGE 4**: Being assaulted by the spirits is also a reference to the aforementioned Troll Steven Spielberg movie. On top of **[Drag]**, you also take **1 [Psychic]** damage on a BAD roll of any kind, and 2 on a MIN. You\'re physically exhausted from your lack of sleep; you lose all your **[Talents]**. You cannot become **[Happy]** by any means.\r\n\r\n> **STAGE 5**: Stage 4 repeats indefinitely. If you get a MIN on this, or any earlier result, the ghosts might even kill you and drag your soul to be one of them. You may die a JUST death, though you may come back with the GHOST template, even if you normally couldn\'t. If you do not, you instead gain a permanent **1 [Weakness]** to **[Psychic]** damage. This stacks if you roll multiple MINs before a GREAT somehow. Rolling a MAX to escape this affliction immediately removes all of this Weakness.\r\n'),
('inebriation', 'INEBRIATION', '[Affliction][Rapid]\r\n', 'Duuuude… I\'m like, so stooooned right now! Ahaha-! You\'ve successfully ignored every warning about how bad it is to consume fucked up foods or drinks from the devil, and now you\'re paying the price. This [Affliction] is usually gained from THE GOOD SHIT precaptchalogues, which give specific Emotions depending on the type of good shit you\'ve consumed.\r\n\r\n> **STAGE 0**: Mmmm… you\'re feeling a little buzzed! Feels good… feels nice. You\'ve consumed something that has exposed you to inebriation. You do not get a save yet- you\'re just kinda getting buzzed! You take **2 [Drag]** as your senses are somewhat clouded.\r\n\r\n> **STAGE 1**: You\'ve allowed time to pass or have consumed more of the substance which activated this whole thing. You failed your **GREAT +APP** roll, and life\'s pretty good. You get the **[Base]** Emotion specified by the source of exposure.\r\n\r\n> **STAGE 2**: Okay… more time has passed, or more shit has entered your system. You failed another **GREAT +APP** roll and it\'s really, really getting you. You get the **[Heightened]** Emotion specified by the source of exposure, as well as a drawback specified. You cannot go past this stage unless you force yourself to by consuming more.\r\n\r\n> **STAGE 3**: Hrrrghk- too much! Too much! Why are you eating more, dumbass? Ever heard of moderation? It\'s like you\'re mocking Troll Sonic\'s Anti-Drug campaigns! You\'re **[Poisoned]**.\r\n\r\n> **STAGE 4**: This was inevitable. You\'re **[Unconscious]**. Idiot.\r\n'),
('psiburn', 'PSIBURN', '[Affliction][Psionic][Rapid]\r\n', 'Oh! Oh, fuck, that HURTS, shit! Nnnmhh- YYYAAAAARRRGH!!! you\'ve got a nasty case of the Psiburn! An unusual [Affliction] that basically gets the acceleration tendon of your Scuttlebuggy jammed in place, except instead of a Scuttlebuggy it\'s your brain, and instead of an acceleration tendon it\'s your psionics. Usually this is received from being a stupid idiot with your psionics, like eating MIND HONEY or getting a little TOO overloaded in an antipsionic field.\n\n> **STAGE 0**: Ohhh, that\'s an unpleasant static chill. Whhrrrhhh. You just got exposed to PSIBURN after failing a **GREAT +APP** roll. You take **1 [Psychic]** damage. You are immune to this effect if you have no psionics. If at any point you succeed your **+APP** roll, regardless of the previous stage, jump to Stage 4.\n\n> **STAGE 1**: KYAAAAAH- what\'s this feeling? You start trembling. You must make a **[Psionic] [Strife]** roll this turn or take **2 [Psychic]** damage. You do **+1 damage** on this turn.\n\n> **STAGE 2**: Oh, god, your head explodes. At least, that\'s what it feels like. You absolutely erupt in psionic energy. You make a **[Legendary] [Psionic] [Strife]** roll against all trolls present. If you don\'t have any **[Psionic] [Strife]** rolls, you gain one; roll GRIEF with **+IMG** and use the **[Psionic]** and **[Mental]** tags instead of **[Physical]**. You do **[Psychic]** damage. You take **1 [Psychic] damage** for every 1 on the dice you roll.\n\n> **STAGE 3**: You are a supernova. You add an extra d8 to your **[Strife]** roll, pushing to a 5d8 or even a 6d8 if possible. If you roll an 8, you do 1 extra damage. If you roll a 1, you do **1 [Psychic]** damage to yourself. This stage repeats until you succeed at your GREAT +APP roll, adding an additional d8 each time.\n\n> **STAGE 4**: Wow! That was an experience! Sucked! You become **[Drowsy]** and **[Godawful]** at **[Psionics]** for the rest of the encounter.'),
('punishmentTime', 'PUNISHMENT TIME', '[Affliction][Rapid]\r\n', 'It\'s time for a VERY… SPECIAL… EXECUTION! PUHUHUHU! Everyone\'s favourite part of true crime is the brutal, ironic punishments the guilty get put through. They\'re gruesome, they\'re humiliating, and they\'re ELECTRIC to watch! Each punishment is custom-made to reflect the perpetrator, usually their job or interests coming back to bite them in the ass. Though they aren\'t always lethal, a Punishment is sure to affect a troll for a long, long time! You are always at full HP when you start this Affliction, and you cannot make any rolls aside from the ones you are asked for. If at any point you hit 0 HP, skip directly to Stage 7.\r\n\r\n> **STAGE 0**: Stage 0 of any Punishment is usually a legal proceeding, like a Splattorney\'s SHOWTRIAL DRAMA or an HONORABLE JUNIOR\'s GUILTY VERDICT ability. If you make your way out of it unscathed, you\'ll surely be fine! If not… well, advance to the next stage.\r\n\r\n> **STAGE 1**: The journey for the execution! You are dragged onto a stage by chains and mechanical arms as the audience cheers and jeers. You must make a **GREAT +APP** roll to muster up your courage. If you fail, you are **[Agitated]** by the proceedings.\r\n\r\n> **STAGE 2**: The big reveal! Curtains are drawn, presenting the theme of the punishment and a name. For example, a Sportsball troll may see a batting machine rigged up like a machine gun called HOME RUN!!, or a Musiscreant may see a mockery of their own shows called SOLD OUT SHOW!!. You must make a **GREAT +APP** roll; if you fail, you are **[Humiliated]** by the reveal.\r\n\r\n> **STAGE 3**: LET THE PAIN BEGIN! You are subject to a cruel and unusual punishment as electronic music scores your screams and the crowd cheers. The batting machine hurls volley after volley of baseball at you, or the robotic arms around your wrists force you to play guitar as the strings electrocute you. Roll a stat that you are **[Talented]** at; on a MIN, you take **12 damage**. On a BAD, take **8 damage**. On an OK, take **5 damage**. On a GOOD, take **4 damage**. On a GREAT, take **3 damage**. On a MAX, take **1 damage**. All of this is **[Unblockable]** damage.\r\n\r\n> **STAGE 4**: Moment of Hope! It\'s customary to give the punished a glimmer of hope and a potential way to break out. Maybe the batting machine runs out of balls, or you somehow yank out of your restraints forcing you to play music! Make a **+GRA** roll in an attempt to escape the torture. On a GREAT or MAX, you escape! Wow, goddamn! On a GOOD or OK, proceed to STAGE 5. On a BAD, take **3 damage** and proceed, and on a MIN proceed to STAGE 5.\r\n\r\n> **STAGE 5**: The Crushing Realization! You AREN\'T going to escape. You AREN\'T getting away with what you did or didn\'t do. That brief glimpse of hope is snagged from you as a plot twist reveals itself; a giant batting robot appears behind you, picking you up and getting ready to use you as a ball, or a backup band of mechanical musicians appear behind you, and their instruments have wires around your ankles. Make a **GREAT +APP** roll; if you fail, you take **2 [Psychic]** damage.\r\n\r\n> **STAGE 6**: The Killing Blow. A humiliating death that wasn\'t at all apparent when you saw the scene at first wracks you with pain. The batting robot bats you into the scoreboard, frying you. The backup musicians play your greatest hits, and the sonic damage ruptures you from the inside. You take **8 [Unblockable]** damage. All **[Drag]** you have accumulated up to this point becomes **[Unblockable]** damage too.\r\n\r\n> **STAGE 7**: The Somber Ending. The camera pans over your defeated body, showing the consequences of crime. How tragic. If you are above **0 HP**, congratulations! You somehow survived with only injured pride, and are simply **[Embarrassed]** for **2 weeks**. If you are below **0 HP**, you are either killed if your death was JUST or HEROIC in your books, or are permanently injured by the incident. Whether you lose a limb, an eye, are bisected, crushed, whatever, you gain a permanent **[Inept]** to one stat unless you buy a prosthetic of some sort or spend a month getting used to your injuries, after which point you learn to live with it.\r\n'),
('radiationPoisoning', 'RADIATION POISONING', '[Affliction][Rapid]\r\n', 'Stop standing in the green goop, you dumb shit! The nuclear waste that litters the rural areas of Alternia is nothing to turn your nose up at; in fact, being too close to a radioactive substance might straight up leave you without a nose, full stop. Watch out!\r\n\r\n> **STAGE 1**: Your skin starts to tickle. That\'s not good! You failed a GOOD +APP roll, you\'re starting to feel queasy and you taste metal. You have a burn on your body somewhere that gives you the **[Poisoned]** condition.\r\n\r\n> **STAGE 2**: Okay, okay, ouch, fuck, ow! Stop that! You take **1 [Somatic]** damage as your body burns from the poison. Your sickness worsens, and you take **2 [Drag]** from **[Poisoned]** at all times.\r\n\r\n> **STAGE 3**: Stage 2 repeats for every turn you do not succeed your **+APP** roll. If you hit **0 HP** like this, you either die (if it was Heroic or Just), take 1 Mutation that is not PSIMATE/HATCHMATE or gain the DROPSHADOW SYNDROME move from the Shadowdropper template.'),
('simptoms', 'SIMPTOMS', '[Affliction][Slowburn]\r\n', 'You went to the wrong concert, and now your world has been changed for the beautiful. Everything is brighter, happier, more wonderful. People are better. Things are better. That drone shooting you is kinda good looking... or maybe the world just seems better in general if you\'re not interested in kissing. Simptoms is an equal opportunity affliction.\r\n\r\n> **STAGE 0**: The world is turning a little brighter. Whether bright in a blackish hatey way, pink in a friendly way, red or gray... it\'s brighter. A **GOOD +PLC** check will remind you that people are bitches though and shrug it off.\r\n\r\n> **STAGE 1**: You failed your **+PLC** check and now you\'re becoming a simp, congratulations! Everyone around you is a little better than you remember, a little prettier maybe. You take **1 [Drag]** the first time you oppose somebody in an Encounter, because strifing someone so cute sucks!\r\n\r\n> **STAGE 2**: Oh no. The world is genuinely becoming a more wonderful place! You love everyone! Or hate everyone! The **[Drag]** you take increases to 2, and you start **[Charmed]** with everyone you meet at the start of an Encounter. \r\n\r\n> **STAGE 3**: You\'re reaching dangerous levels of simpdom now, Klamni. You now remain **[Charmed]** even after the first time you are attacked by someone, but a second strike will dispel it as usual. You\'re starting to feel truly happy with the world too. You also start Encounters **[Giggling]** as, well... the world is pretty lovely, isn\'t it? That\'s kinda funny you didn\'t always think so!\r\n\r\n> **STAGE 4**: You\'re a simp. I\'m sorry. It\'s critical. You are **[Fascinated]** with everyone you meet now, and it’s not dispelled when you are harmed, instead dropping to **[Charmed]** and being treated as in Stage 3. You are always **[Happy]** and continue **[Giggling]**, which cannot be removed under any circumstances anymore. STAGE 4 continues indefinitely until you succeed your **+PLC** check.\r\n'),
('theHemocough', 'THE HEMOCOUGH', '[Affliction][Slowburn]\r\n', 'Cough cough cough. You look down at your hanky. OH NO. IT’S STAINED WITH BLOOD. You look around, and quickly tuck it away before anyone can notice. Has this ever happened to you? Well, you just might have the HEMOCOUGH, Alternia’s weirdest disease! When you have the HEMOCOUGH, you cough up weird phlegm that just happens to look like your blood colour, and are afflicted with a destabilizing paranoia. YOU’RE HEALTHY. YOU’RE TOTALLY HEALTHY. GO AWAY. On its own, it’s not that bad… but it does mean you’ll violently avoid medical treatment. You’re like, the guy who got bit in a Shadowdropper movie, or something. \r\n\r\n> **STAGE 0**: You failed your **GOOD +GRT** roll against whatever exposed you, and you’ve had your first cough. However, you really don\'t want people to know, even if you can’t explain why. You just take **1 [Drag]** for now.\r\n\r\n> **STAGE 1**: Aw, junk, that\'s a mighty bad cough you got going on there, bud. When you get an OK or lower **[Manipulate]** roll, you cough a little, and then take **1 [Drag]** as you assure everyone it’s fine, you’re totally fine, don’t worry about it. Whenever you see a Docterror or some other troll who can heal **[Afflictions]**, you must roll to ABSCOND or you take **1 [Non-Lethal][Psychic] damage** every turn.\r\n\r\n> **STAGE 2**: YOU’RE FINE! YOU DON’T NEED A DOCTOR, YOU’RE PERFECTLY HEALTH! KAFF KAFF KAFF! You are permanently **[Agitated]** as you look around for people who aren’t DELUDING themselves into thinking you might be poorly. YOU’RE GOOD! It’s NORMAL to cough up blood!\r\n\r\n> **STAGE 3**: Oh sweet gog you’re really in it now! You have yellow tape and red strings connecting diagrams along your whole hive to find some unknown cure (the catch is the only cure is to literally visit a doctor) but you promise that this time you got it ! Swear! Anytime someone **[Manipulates]** you, instead of taking the effect you can instead take **2 [Non-Lethal] [Psychic]** damage! You can’t make any **[Downtime]** rolls as you’re enamored to research for another cure. Finally, your ABSCOND rolls are always **[Legendary]**.\r\n\r\n> **STAGE 4**: You constantly cough, and have a permanent STAGE 0 Hemocough ! The rest of the events keep looping from 1-3.\r\n'),
('theSniffles', 'THE SNIFFLES', '[Affliction][Slowburn]\r\n', 'Ah… AH… ACHOO! Bleh. You have the most dreaded of illnesses: the Sniffles. Your nose is clogged with gunk, your throat is clogged with gunk, your brain is clogged with gunk… you’re a sorry sight to behold! Caused by bacteria that thrives in the cold, the Sniffles isn’t so much life threatening as it is a funny plot hook for a sitcom episode about being sickly.\r\n\r\n> **STAGE 0**: You failed your **GOOD +APP** roll against whatever exposed you. You’re mostly fine, except… ah… ACHOO! Bleh! You sneeze periodically, meaning rolls to find you when you’re **[Hidden]** are **[Tiered Up]**.\r\n\r\n> **STAGE 1**: You get the feeling you dun goofed, and are feeling somewhat sickly. All your rolls have a **-1 [Nerf]** to them because you can neither think nor act exactly right.\r\n\r\n> **STAGE 2**: [gross sniffling noises] Yeah, okay, you’re definitely ill. Your nose is clogged, there’s crumpled tissue paper everywhere, and you look very visibly tired. You are constantly **[Tired]**, and have a **-2 on all rolls**. Whenever you fail a roll in someone’s presence, you sneeze at them, exposing them to the Sniffles too!\r\n\r\n> **STAGE 3**: You can’t leave the hive! That’s how poorly you are! Oh, to have some hot soup and maybe a nice warm robe on… you are constantly **[Exhausted]** and have a **-3 on all rolls**.\r\n'),
('trickstersGambit', 'TRICKSTER\'S GAMBIT', '[Affliction][Slowburn]\r\n', 'Congratulations! You’ve been hit with the oldest trick in the book! Whether or not you found some free candy in your walls, or found something drastically wrong with reality that scarred you permanently, you’re now on your way to becoming a TRICKSTER! Everything that shouldn’t be funny, or should scare you, instead fills you with joy and glee! You laugh in a somewhat off-putting way in nearly every situation, and your skin has a somewhat shiny look to it. \r\n\r\n> **STAGE 0**: You failed a **GREAT +RAS** roll against whatever exposed you to this, and now you’re feeling sickly sweet. You must’ve breathed something in you shouldn’t have, seen something that knew you were there. Any **[Heightened]** negative emotion automatically stacks over to become a **[Base]** positive emotion.\r\n\r\n> **STAGE 1**: You’ve found yourself liking sweeter and sweeter things, your personality is slowly taking a shift to a JOLLY, CANDY LOVING JOKER. In any encounter, you feel really hyper for no good reason even in the direst of circumstances, though it can be brought down by an overwhelming negative emotion.\r\n\r\n> **STAGE 2**: Okay, wow, something is wrong. Something is WRONG, SOMETHING IS WRONG. Your emotions, they’re all messed up. You lost your palmhusk for like, 5 whole macros, and you didn’t even care. No meltdown, no anxiety, nothing. In fact, it kind of feels like life can’t drag you down right now. As long as you have this affliction, you can’t have more than **3 [Drag]**. Any excess drag you receive is instantly translated to **[Boost]**, as you take a more positive outlook on the situation. \r\n\r\n> **STAGE 3**: After a long week of contemplating, you’re much happier the way you are. You’ve already started to buy candy in bulk, your favorite colors are something other than black and dark gray, and you’ve got a certain... Something, in your eyes. The dust of the candy-ridden void embeds itself into you as it was ingested, and you may take the TRICKSTER template as you finalize your transformation to a MOED MOSTE TRICKSEY :)!\r\n');
INSERT INTO `custodian` (`key`, `title`, `text`) VALUES
('aquatic', 'AQUATIC', 'It\'s a water custodian! Nothing in the water is going to be able to get around unaccosted by this thing. Especially when they get pulled under. Their targets are given the DROWNING **[Affliction]** if they are in the water. The target has a **-2 [Nerf]** on rolls against the **[Affliction]** on a **GREAT**, and a -4 on a **MAX**.'),
('asshole', 'ASSHOLE', 'Your custodian is a bluh bluh huge bitch. It deals **1/2/3 [Somatic]** damage… to EVERYONE present. Including you. This doesn\'t have the **[Strife]** tag.\r\n'),
('cryptid', 'CRYPTID', 'Your custodian doesn\'t approach you, instead creeping in the distance. Your target\'s **[Analyze]** rolls are **[Godawful]** for 2/3/4 turns as they get distracted by… that thing over there… \r\n'),
('camouflaged', 'CAMOUFLAGED', 'Camouflaged: It lurks and seeks out its prey with immaculate camouflage. You become **[Hidden]**, and SPOT rolls against you are at a **-2/3/5 [Nerf]**, but you\'re also **[Trapped]** until you stop being **[Hidden]**.\r\n'),
('constricting', 'CONSTRICTING', 'Your custodian is wreathed in tentacles, or maybe it has a serpentine shape. Regardless, it can be used to hamper the movement of others. You expose the target to the CHOKING **[Affliction]**. The target has a **-1 [Nerf]** on rolls against the **[Affliction]** on a **GREAT**, and a **-2** on a **MAX**.\r\n'),
('energized', 'ENERGIZED', 'It breathes fire, or something similar enough! Whether it’s lightning strikes, using psionics or breathing fire like a snazzard; it falls under this. Choose an **[Energy]** type your CUSTODIAN is attuned to. Your CUSTODIAN supercharges your weapon, changing its **[Energy]** type for **2/3/4 turns**. \r\n'),
('eldritch', 'ELDRITCH', 'Something unnatural is up with this thing… something is just… wrong with it. What color is that? Is its skin writhing?! It does something freaky, and all enemy **[Magic]** rolls are **[Inept]** for **2/3/4 turns**. \r\n'),
('flying', 'FLYING', 'This motherfucker has WINGS or whatever! It picks you up and starts **[Flying]** for **1/2/3 turns**. During this time, your ABSCOND rolls have a **+3 [Buff]**.\r\n'),
('fluffy', 'FLUFFY', 'Your custodian is astoundingly fuzzy! You get a **GOOD/1 GREAT/2 MAX** WORDPLAY result as you stroke it.\r\n\r\n'),
('fancy', 'FANCY', 'Well la-dee-dah! You got a dignified custodian, you snob. It waits at your side, ready to aid you in your prestigious efforts. Yours and your allies’ FRAYMOTIF rolls get a **1/2/3 [Buff]** next turn.\r\n'),
('ghost', 'GHOST', 'Your custodian is only with you in spirit, unfortunately. Revealing a Ghost custodian gives you the **[Cullbait]** tag on trolls who see it, but also **[Scares] all enemies for **2/3/4 turns**.\r\n'),
('hostile', 'HOSTILE', 'GRAWRRRRR GRARRR GROOOOAAWWWR. Your custodian ravages the target! You do **1/2/3 [Somatic]** damage on a **GOOD/GREAT/MAX**, or reduce the damage by 1 and make the target **[Bloodied]**. This has the **[Strife]** tag.\r\n'),
('intelligent', 'INTELLIGENT', 'This custodian was bred for its intelligence, and it shows. It gives you a **GOOD/GREAT/MAX PROBLEM SLEUTHING** roll!\r\n'),
('kind', 'KIND', 'Your custodian loves you very much, and makes sure you know this! It heals **2/3/4 [Drag]**, if you have any.\r\n'),
('loyal', 'LOYAL', 'Your custodian is dedicated to you, and will sooner die than allow a charge to fall to harm! Your target\'s next **[Strife]** roll has a **-1/2/4 [Nerf]** as they jump in the way to protect you. \r\n'),
('mindAltering', 'MIND ALTERING', 'Your custodian has some method of **[Control]**ing others. You get a **GOOD/GREAT/MAX** Cerulean Mastermind FREAKY EYE effect.\r\n'),
('massive', 'MASSIVE', 'Look at the size of em, corr blimey. With a THONK, your custodian triggers the ROCKS FALL Hazard. All combatants (including yourself) take **1/2/3 [Drag]**.\r\n'),
('magic', 'MAGIC', 'The power of belief resides within your custodian! Its magic fairy dust sprinkles on you, and you gain **1/2/3 [Boost]**.\r\n'),
('nurturing', 'NURTURING', 'Wow, your custodian said you could have coping skills? It croons over you, you gain **1/2 [Boost]** or **[Heal] 1/2 HP** on a **GREAT/MAX**.\r\n'),
('negligent', 'NEGLIGENT', 'Your custodian really doesn’t give a shit whether you live or die, apparently. They leave the encounter. When you have this Feature, you can\'t actively select it, but you do roll 1d8 every time you use ALTRICIALIZE. On a 1 or 2, they leave instead of the effect you\'d normally pick. You lose all emotions immediately, become **[Numb]** on a **GREAT** and start **[Dissociating]** on a **MAX**. You can\'t use ALTRICIALIZE again.\r\n'),
('oblivious', 'OBLIVIOUS', 'Your custodian is just… it’s doing its best but it’s a miracle you made it to pupation. Your momma never was much help with schoolfeeding. You take **1/2/3 less damage next turn** as you hide behind your custodian.\r\n'),
('prankster', 'PRANKSTER', 'That\'s right, PIE EM! Your custodian aids you in prankery. You get a **GOOD/GREAT/MAX** SHENANIGANS roll. \r\n'),
('pathetic', 'PATHETIC', 'Oh, good god. That\'s the saddest fucking thing I\'ve ever seen. This thing raised you? Shit. Your custodian has no other ability. All people who see this are **[Embarrassed]** for **2/3/4 turns**, yourself included. Maaaan…\r\n'),
('registeredVoter', 'REGISTERED VOTER', 'Dogs can vote now! Skyli said so! Your lusus votes for you in the local election, giving you 1/2/3 base positive emotions of your choice as you swell with pride. This does not actually give you any authority as elections of any kind are not formally recognized by the Alternian government. You have to actually roleplay your lusus submitting a ballot and voting for you for this to take effect.\r\n'),
('swarm', 'SWARM', 'One custodian? Pshhh. How about THIRTY? Your target becomes **[Stressed]** for **2/3/4 turns**. EEK! A MOUSETAMPEDE!\r\n'),
('strict', 'STRICT', 'This custodian demands success and victory, not slacking and “veedeeoh gaymes.” You cannot roll lower than an **OK** for **2/3/4 turns**, but you take **2 [Drag]** on **OKs**, **3 [Drag]** from **BADs** and **4 [Drag]** from **MINs** as your custodian gives you a deathglare. \r\n'),
('slimy', 'SLIMY', 'It’s slippery. It’s slimy. Dear gog, is it oozing on the floor? Eeeeeew. It’s a **[Lengthy]** action to **[Physically] [Strife]** you for **1/2/3 turns**.\r\n'),
('telekinetic', 'TELEKINETIC', 'Gravity is for losers! Your custodian can twist the world around it. Their targets start **[Flying]** for **1/2/3 turns**. This is a **[Psionic]** effect.\r\n'),
('ugly', 'UGLY', 'This custodian is an ugly sumbitch I tell you what. The target is **[Disgusted]** for **2/3/4 turns**.\r\n');
INSERT INTO `downtime` (`key`, `title`, `tags`, `text`) VALUES
('rumorhunger', 'RUMORHUNGER', '[Analyze][Downtime]\r\n', 'On Alternia, people talk. Probably because it\'s an entire planet of barely supervised kids, teenagers and young adults with nothing better to do but start drama and kill each other. All in all, it\'s not hard to find out what\'s what. When you want to get the Goss on a target, roll **+RAS**.\r\n\r\n> **MIN**: Your messenger rust gets captured, your psionic brain waves are picked up or you just straight up accidentally asked their bestie for life about them. Whatever the reason, you\'re outed. Your target receives a MAX result RUMORHUNGER on you as you out yourself to them.\r\n\r\n> **BAD**: You\'re not as sneaky as you think you are! Word gets out that someone is after your target\'s info, and they definitely hear about it themselves. You\'re not outed as the one looking after it though... yet. Your target gets **1 [WHAM]** at the start of your next encounter together.\r\n\r\n> **OK**: There\'s a delay. Your messenger rust got eaten by a pigeon. This sucks. You receive some information on your target, such as their plans or where they are, but it might be inaccurate... or about someone else entirely. Clouder\'s discretion for how accurate it is and who it is about.\r\n\r\n> **GOOD**: Word down the grapevine is that Enpeci is plotting a heist... you in? You learn something about your target that they might have thought to be a secret, such as their plans or where they are. In your next encounter together, you may begin it **[Hidden]** or with **2 [Boost]**, your choice.\r\n\r\n> **GREAT**: No way, you captured their messenger rust!? Score! You get a clear, detailed understanding of something your target is up to. In your next encounter together, you may begin it with **[Hidden]** and **2 [Boost]**. If you choose not to be **[Hidden]**, you start with **3 [Boost]** instead.\r\n\r\n> **MAX**: You might as well be in their walls like that one Grumblr meme, because you\'re listening in. You gain a complete understanding of what they\'re up to, as well as one critical piece of information to your own plans if any exists. If you use this information to start an Encounter, you may begin it with **[Hidden]** and **3 [Boost]**. If you choose not to be **[Hidden]**, you start with **3 [Boost]** and **[Smug]** instead.\r\n'),
('smearCrusade', 'SMEAR CRUSADE', '[Chicanery][Downtime]\r\n', 'Oh no, girl they did not. They just did the wrong thing by posting that. Or saying that. Or wearing that. Or existing with that (blood color). It\'s time to take to the streets, because you\'re about to start a public disturbance. Doesn\'t matter if you\'re going behind their backs or yelling at them on the streets! When you want to publicly debate, berate or otherwise smear a target, roll **+PLC**.\r\n\r\n> **MIN**: YOU ARE BESET UPON BY THE CROWDS! HOW DARE YOU SMEAR DEAR SWEET ENPECE?! You get a **MAX** except just kidding roles reversed you\'re the **[Agitated]** and damaged one.\r\n\r\n> **BAD**: Wait, what do you mean you\'re wrong? The public... disagrees with you!? Your rash language turns people against you. Your next encounter with the target starts with you being **[Stressed]** until **2 turns** after combat starts.\r\n\r\n> **OK**: Everyone thinks you\'re both cringe and you get middling pitchvotes on Shreddit\'s /s/publiclashouts subshreddit when some gold uploads a video. Or, you know, nothing happens because nobody cares about two people arguing on the sidewalk, or Chittr, or anywhere. \r\n\r\n> **GOOD**: Can you believe them!? Right? Right? You manage to sway the public opinion against the other. In your next encounter with the target, your target begins **[Stressed]** until **2 turns** after combat starts as the public turns on them.\r\n\r\n> **GREAT**: BOOOOO!! BOOOOOOO! You get a **GOOD**, but the target is **[Agitated]** for the first turn.\r\n\r\n> **MAX**: WOW! YOU WON IN THE COURT OF PUBLIC OPINION! You get a **GREAT**, and their HP is 2 lower than normal as they feel people hate them! Yesssss!\r\n'),
('posturize', 'POSTURIZE', '[Flourish][Downtime]\r\n', 'Sometimes… you wanna fluff up your reputation a little! Make yourself a little more impressive to a person. Get their attention, you know? Strut your stuff! That\'s when POSTURIZING comes into play. Whether through walking around and wearing nice clothes in places you know they\'ll be, talking to people they talk to in hopes they\'ll think of you or otherwise just marketing yourself, when you wanna get attention roll **+GRA**.\r\n\r\n> **MIN**: Eurgh. Who\'s this poser? You garner bad press, and worse, your target is a little put off by how hard you\'re trying. Your next three **[Downtime]** rolls are **[Inept]** because of how thoroughly embarrassing that is.\r\n\r\n> **BAD**: Nothing happens, because dude, what are you doing. You look stupid. Your next **[Downtime]** roll is **[Inept]**.\r\n\r\n> **OK**: You think they noticed you! Maybe? Who knows. \r\n\r\n> **GOOD**: Aha! They DID notice you! If they mention you in an encounter you\'re not in over the next week, they get **1 [Hold]** to give them a **[Boost]** for free over the week; it\'s flattering that you\'re trying to get their attention. Being on their lips is sure to make you more popular in their eyes!\r\n\r\n> **GREAT**: EXCELLENT! There\'s no way they aren\'t impressed! You get a **GOOD**, but if the target talks at length about you, it increases to **2 [Boost]**. You also get this **[Hold]** if they start an encounter with you!\r\n\r\n> **MAX**: YEAHHHHHH! YOU DID A GREAT JOB! YOU\'RE ALL THEY CAN THINK OF, MAYBE! This gives you a **GREAT**, and exposes the target to the SIMPTOMS affliction.\r\n'),
('moneymakery', 'MONEYMAKERY', '[Flourish][Downtime]\r\n', 'Everyone out there needs to make some cash sometimes! It\'s just how the world works. So when you wanna put in some elbow grease and EARN it… roll **+APP** for a fair and equitable time! You can only roll this move once a day.\r\n\r\n> **MIN**: UH OH DIPSHIT! YOU SOMEHOW GOT INTO SOME SERIOUS TROUBLE! Maybe you borrowed from a Juggalo Mafia, maybe you stole something… point is, you must immediately start an encounter with either an ANGRY MOB, a DRONE STRIKE or a STAMPEDE, whatever makes the most sense! In the event that none of the three make sense then you can instead take a penalty of losing twice your **GREAT** result in LUX, potentially going into the negatives.\r\n\r\n> **BAD**: Urrrrgh. You didn\'t make any money at all. Life fucking sucks!\r\n\r\n> **OK**: You\'re certainly working hard. You can reroll this move! Maybe you\'ll do better now!\r\n\r\n> **GOOD**: Success! You make **1 LUX** if you\'re Poor or Decent, **2 LUX** if you\'re Average or Well-Off or **3 LUX** if you\'re Rich or Ultrarich. You make **1/2 LUX** if you\'re Destitute. Lol.\r\n\r\n> **GREAT**: Now we\'re cooking with gas! You get a **GOOD**, +1! If you\'re Destitute, you just get **1 LUX**.\r\n\r\n> **MAX**: WOW! You\'re ROLLING in surplus wealth! You get a **GOOD** +2! If you\'re Destitute, you get **2 LUX**.'),
('bashNRun', 'BASH-N-RUN', '[Chicanery][Downtime]\r\n', 'Not every fight has to be a dramatic duel, or a 3x Multishowdown. Sometimes, the better choice is just... throwing a brick through a window. Or skating by and hitting them with a baseball bat before speeding off. Or however else you might be about to cause physical harm. When you want to hit and run a target, roll **+GRT**.\r\n\r\n> **MIN**: Fuck! Damn! You got shot! What the fuck! Maybe not shot, but something equally bad happened. Maybe a patrol drone saw you, or you just tripped hive security. No matter what it is, in your next Encounter with the target, **3 VP** of yours becomes unavailable and you begin with **2 less HP**.\r\n\r\n> **BAD**: Is THIS what you call vandalism? Putting a rude sticky note on their door? What are you, 6? You lose **1 VP** in your next encounter with the target as you spend too much money on an entirely ineffective vandalism attempt.\r\n\r\n> **OK**: You throw a brick, they throw it back. Everyone loses. You and your target both lose **1 VP** in your next Encounter with them.\r\n\r\n> **GOOD**: You smash stuff up. Whether it\'s a brick through a window or hitting somebody before they can retaliate, you disable a HIVECRAFTING UPGRADE of theirs for their next encounter at hive. \r\n\r\n> **GREAT**: WHEW! DESTRUCTION! You disable two HIVECRAFTING UPGRADE of theirs for their next encounter at hive.\r\n\r\n> **MAX**: Did you just use a bomb on them? That\'s a little much, don\'t you think? Whatever it is you did to your target, it hurts. You disable any and all of the target\'s HIVECRAFTING UPGRADES for their next encounter at hive. \r\n'),
('seekAdventure', 'SEEK ADVENTURE', '[Flourish][Downtime]\r\n', 'WHO WANTS TO GO KICK A SNAZZARD\'S ASS! There\'s tons to do in the wild world of Alternia, and it never backfires, ever! When you want to drag people out to kick monster butt, roll +HUB. You can roll this move as many times in a row as you like to continue hunting monsters after you slay one; you get a +1 on your D8 rolls (cumulative!) if you do this, but you can\'t rest and heal between encounters. Use Chapter 22: HABITATS to get roll tables to help randomly select monsters and hazards for your encounters!\r\n\r\n> **MIN**: Uhh. Uh oh. That\'s, uh. That\'s a COLOSSUS. And also there\'s a HAZARD going on. Uhhh. Not. Not great. Hey, if you somehow win, you all get **TREASURE V** though?!\r\n\r\n> **BAD**: You don\'t find any monsters. Fight each other. Winner gets the other person\'s stuff. Or don\'t, I\'m not your dad.\r\n\r\n> **OK**: You find… a Level 0 monster. Great. This means nothing to you. But whoever deals the killing blow gets **Treasure I**!\r\n\r\n> **GOOD**: Aha! STUFF! Roll a d8, and have the following encounter with the following loot if you beat it. If you get a Hazard, roll 1d8 every round after everyone\'s had a turn; on a 1, the Hazard begins! If you search in a specific location, you might narrow down the type of monsters or hazards you encounter; see CHAPTER 22: HABITATS for ideas.\r\n\r\n> 1. A random level 1 monster. **Treasure I** to whoever deals the final blow.\r\n> 2. A random level 1 monster, and a random Hazard! **Treasure I**.\r\n> 3. A random level 2 monster! **Treasure I**.\r\n> 4. A random level 2 monster and a random Hazard! **Treasure II**.\r\n> 5. A random level 3 monster! **Treasure II**.\r\n> 6. A random level 3 monster and a random Hazard! **Treasure III**.\r\n> 7. A random level 4 monster! **Treasure III**.\r\n> 8. A random level 4 monster and a random Hazard! **Treasure IV**.\r\n\r\n> **GREAT**: WANNA PUSH YOUR LUCK?! You get a **GOOD**, but you can choose to add a second d8 roll, stacking two encounters together! You gain the sum of the total Treasure plus 2.\r\n\r\n> **MAX**: JEEEEEGUUUUUS. That\'s SO MUCH. WHAT IS GOING ON. You can add a THIRD ROLL, if you choose, and DOUBLE the total Treasure.\r\n'),
('haxxAttaxx', 'HAXX-ATTAXX\r\n', '[Downtime][Tech]\r\n', 'Ugh! Someone just insulted your honour online! Better prove them right by sending them a Trojan! Your mastery over tech is pretty impressive, and you vow to ruin anyone who doubts you. When you wanna fuck with someone\'s computer, roll +PSP.\r\n\r\n> **MIN**: Wow. You fucked up. You clicked a virus, you tried to help the fuschia princess who claimed to need your help, you turned off ad blocker— something AWFUL happens. You drop two Wealth Levels. Great work.\r\n\r\n> **BAD**: Fuck! You can\'t get through their firewalls! Nothing happens.\r\n\r\n> **OK**: Maybe… maybe… it\'s taking longer than normal, but it could go either way. Reroll HAXX-ATTAXX.\r\n\r\n> **GOOD**: HAHA! GOTCHA! You give them a biovirus. Select one of the following options.\r\n\r\n> **HARDGRUB DISEASE**: Keheheh. You give their phone a fever! Cough cough cough… their **[Tech]** rolls are at a **-2 [Nerf]** in your next encounter with them, and their HAXX-ATTAXX rolls are **[Inept]** until then.\r\n\r\n> **ENGAGE MASSIVE TROLLING**: You force them into a one on one WORDPLAY duel online, except that all rolls use **+PSP**. Literally all their devices show your texts, so they can\'t not fight! Loser\'s internet cuts out.\r\n\r\n> **HIVEPOX**: The biotech in their very home is sluggish! You disable one of their HIVECRAFTING Upgrades. They need to either ask you nicely to stop, or beat the shit out of you.\r\n\r\n> **CAEGARGLUTTON**: You send a parasite into their bank account that LITERALLY eats their money. Their Wealth Level drops by 1 until they either use Treasure or beat you up.\r\n\r\n> **SELF-DIGESTING CODE**: You make the target\'s biotech literally eat itself. Ewww… the target is **[Disgusted]** in their next encounter with you. \r\n\r\n> **LOWER DEFENCES**: Nothing… for now. You\'re just working hard to leave them COMPLETELY exposed… Keheheh… your next HAXX-ATTAXX roll against them gets a **+1 [Buff]**; this is cumulative, so if you pick it again it\'s a **+2 [Buff]**, a **+3 [Buff]** until you finally take a different option. \r\n\r\n> **GREAT**: Yeaaaah! That\'s what I\'m talking about! You include, like, a cool logo or a video of you with the hack. Choose two HAXX. If you want to keep using LOWER DEFENCES, pick it twice.\r\n\r\n> **MAX**: Oh god. You expose them to a legendary program which vanquishes machines and, supposedly, curses the recipient and everyone they ever meet. They are exposed to the DOUBLE MOBIUS REACH AROUND VIRUS **[Affliction]**.\r\n'),
('qualityTime', 'QUALITY TIME', '[Flourish][Downtime]\r\n', 'Chill out! Come on, man, not everything is about doom and gloom! Maybe you wanna go on a lil date with a loved one. Maybe you wanna play FLARP with your friends. Maybe you wanna run around and play pretend, or paint a picture, or eat some food… look, the point is, moments of peace with you and your loved ones exist, and you should be happy to indulge yourself! When you wanna have a good time, roll **+IMG**.\r\n\r\n> **MIN**: AWFUL TIME! SOMETHING HAS GONE AWRY! You start your next encounter unable to gain any **[Boost]**. What went wrong? Hopefully, it doesn’t have any… lasting narrative consequences..! That would suuuuck.\r\n\r\n> **BAD**: You had a bad time. Life is cruel like that.\r\n\r\n> **OK**: You know what? Life isn’t all that bad! Your next encounter starts you with **1 [Boost]**.\r\n\r\n> **GOOD**: Hey, you had a great time, even! You start your next encounter with **2 [Boost]**.\r\n\r\n> **GREAT**: Wowee! You’re filled with… a good feeling?! How is that POSSIBLE on such a hell planet! You have **2 [Boost]** and the **[Hopeful]** condition at the start of your next encounter.\r\n\r\n> **MAX**: LIFE IS GREAT LIFE IS GREAT LIFE IS GREAT LIFE IS GREAT! You have **2 [Boost]** and the **[Inspired]** condition at the start of your next encounter as you feel AWESOME because you had THE BEST NIGHT EVER!\r\n');
INSERT INTO `effect` (`key`, `title`, `text`) VALUES
('ablaze', 'ABLAZE', 'A status effect where you take **2 extra [Blaze] [Somatic]** damage at the end of each of your turns until you take an action to stop, drop and roll! **[Resistance]** to **[Somatic]** damage does not affect this damage.\r\n'),
('bloodied', 'BLOODIED', 'A status effect where your body is wracked with wounds! Your blood colour is visible while **[Bloodied]**, and the first time an effect would **[Heal]** you, you regain **0 HP** and instead cure **[Bloodied]**.\r\n'),
('blinded', 'BLINDED', 'A status effect where you can’t see! Everything is **[Hidden]** from you, and if you find them with a PROBLEM SLEUTHING roll, or they reveal themselves to you, they resume being **[Hidden]** after a turn. Effects which require visual stimuli do not affect you. If you are permanently Blinded, you have the **[Permablind]** condition. If your condition lasts more than **3 turns**, you can take **an action** to rub your eyes and remove the condition.\r\n'),
('clumsy', 'CLUMSY', 'Where... are your feet. Where are your hands. You are stubbing your everything on anything. Your **[Physical]** rolls all take a **-2 [Nerf]**.\r\n'),
('deafened', 'DEAFENED', 'FUCK, YOUR EARS! OW! A status effect where a ringing in your ears absolutely fucks you over; your **+PLC** is **[Inept]** since you can\'t focus on words to be charming with, but you also gain **2 [Verbal] [Resistance]**. \r\n'),
('distracted', 'DISTRACTED', 'Ngh— sorry, can you repeat yourself? You just aren\'t paying full attention. Your **[Mental]**, **[Manipulate]** and **[Psionic]** rolls all take a **-2 [Nerf]**.\r\n'),
('floorbound', 'FLOORBOUND', 'A status effect where you are lying on the floor like a big dumb wriggler. You are prone, and you need to spend an action to stand up, or become **[Inept]** at all **[Physical]** rolls. Knocking a **[Flying]** target Floorbound will end their flight.\r\n'),
('flying', 'FLYING', 'A status effect where you begin hovering or flying in the air. **[Physical]** rolls made against you are **[Inept]** and opponents cannot roll **CAN\'T ABSCOND, BRO** on you unless they\'re also **[Flying]**. Being knocked **[Floorbound]** will end your flight.'),
('gushing', 'GUSHING', 'A status effect where you\'re bleeding but, like, a lot? Looks like someone nicked an artery! You take **2 damage** at the start of your turn every round until you are subject to a **[Heal]** effect. Being immune to **[Bloodied]** does not stop you from **[Gushing]**. Only Colossi can cause **[Gushing]**. **[Gushing]** is not a heightened version of **[Bloodied]**.\r\n'),
('hidden', 'HIDDEN', 'A status effect where you are not being directly observed by your target. Rolling any **[Physical]** or **[Strife]** moves against you is much harder than normal with a **-3 [Nerf]** to try. A GOOD PROBLEM SLEUTHING roll discovers your basic whereabouts, but doesn’t spot you directly; the target’s **[Physical]** or **[Strife]** moves against you take a **-1 [Nerf]**. A GREAT roll spots you, and removes the Hidden effect. A MAX roll sees you so well that you cannot benefit from being Hidden for the next **5 rounds**. You are revealed as soon as you choose to be or roll a **[Strife]** move against them.'),
('permablind', 'PERMABLIND', 'You are blind forever. This isn’t as sucky as you’d think! Your other senses heighten, allowing you to hear, smell or even taste your opponents. Nobody ever benefits from the **[Hidden]** condition against you, though effects which require visual stimuli still don’t affect you. \r\n'),
('permadeaf', 'PERMADEAF', 'Only chumps need to actually hear stuff. You are a deaf, Deaf, or HoH troll, and can manage pretty easily all things considered. Lip reading, sign language, hearing aids, etc, help you communicate with other trolls; your sign language mostly shows up in a dialogue box, so people still understand you. You have **2 [Resistance]** to **[Verbal]** damage.\r\n'),
('poisoned', 'POISONED', 'A status effect where you have become sickened by something. Starting on your first turn after you are Poisoned, you begin taking **[Drag]**; you gain **2 [Drag]** on that **first turn**, then **1 [Drag]** every turn after until you are the subject of a healing effect.\r\n'),
('quickened', 'QUICKENED', 'A status effect where you have one extra action on your turn. You can get this up to twice per encounter, giving you an absolute maximum of **4 actions** per turn. Being **[Quickened]** and **[Slowed]** at once removes both effects.\r\n'),
('slowed', 'SLOWED', 'A status effect where you have one less action on your turn. You cannot have less than **one action** per turn. Being **[Quickened]** and **[Slowed]** at once removes both effects.\r\n'),
('soggy', 'SOGGY', 'You\'re all wet! Argh! Ugh, you look like a damp purrbeast! Your **[Fashion]** items no longer work. You have **1 [Weakness]** to **[Electric]** damage like this, but **1 [Resistance]** to **[Fire]** damage.\r\n'),
('stunned', 'STUNNED', 'A status effect where you receive **one less action** on your next turn.\r\n'),
('trapped', 'TRAPPED', 'A status effect where the target cannot roll LET’S STRIFE or SWASHBUCKLING because they\'re too stuck in one place. Taking an action to remove yourself from your current Trapped position removes this condition.\r\n'),
('unconscious', 'UNCONSCIOUS', 'A status effect where you cannot take any actions until awoken, usually by a loud noise or any moves successfully targeted at you. You are **[Floorbound]** when you fall Unconscious unless you were already sitting/laying down.\r\n'),
('weakness', 'WEAKNESS', 'A state of affairs where you take **1 extra damage** from certain damage types. Weakness is essentially a mini-wham, dealing extra damage to an opponent once unless a move specifies otherwise.\r\n');
INSERT INTO `emotion` (`key`, `title`, `text`) VALUES
('hopeful', 'HOPEFUL', '**[Base][Opposite: Dread]**\r\nAn Emotion where you believe in a better tomorrow! You can do this! Any time you use **[Boost]** to hype up a roll, you get a **+1 [Buff]** to this roll for free!'),
('inspired', 'INSPIRED', '**[Heightened][Opposite: Despair]**\r\nAnime… IS REAL! You WILL win, and you’ll save the day! Whenever you gain **[Boost]**, you gain 1 extra for free. If a trigger would render you **[Hopeful]** while you are Inspired, you gain **2 [Boost]**. This emotion does boost **[Boost]** gained through **[Emotions]**.\r\n'),
('smug', 'SMUG', '**[Base][Opposite: Embarrassed]**\r\nHeheh. Not too shabby, huh? Better than some people, I\'ll say. When you roll a **GREAT/MAX** on a roll, you get a **+1/+2 [Buff]** to rolling moves with the same stat next turn! Sweet!	\r\n'),
('supercilious', 'SUPERCILIOUS', '**[Heightened][Opposite: Humiliated]**\r\nTEEHEEHEEHEE. Yeaaaah, you\'re GREAT, and everyone else is maaaaad. You\'re the living embodiment of the knife cat right now, you\'re just OOZING with smugness. When you roll a **GREAT** or **MAX**, you become **[Talented]** at the stat you rolled next turn, or for **2 turns** on a **MAX**. If you were already **[Talented]**, you become **[Legendary]**. If a trigger would render you **[Smug]** while you are Supercilious, you gain **2 [Boost]**.'),
('peaceful', 'PEACEFUL', '**[Base][Opposite: Stressed]**\r\nYou\'re so chill right now bro. It all just rolls off you like duck water. Any **[Drag]** you would gain is reduced by 1 to a minimum of 1. It\'s okay… you\'re aaaall good. '),
('serene', 'SERENE', '**[Heightened][Opposite: Agitated]**\r\nYou\'ve found inner peace. Self actualization ahoy. Any obtained **[Drag]** is halved, rounded down. This reduces **1 [Drag]** to 0. Aaaaaall good. Nothing to worry about here. If a trigger would render you **[Peaceful]** while you are **[Serene]**, you gain **2 [Boost]**. '),
('enthusiastic', 'ENTHUSIASTIC', '**[Base][Opposite: Tired]**\r\nDo you... do you wanna hear about my special interest? I promise it\'s really cool!! You gain a +1 to your highest stat. If you have multiple highest stats, declare which one you\'re choosing. '),
('passionate', 'PASSIONATE', '**[Heightened][Opposite: Exhausted]** \r\nYES! YOU CARE SO MUCH! THIS IS THE THING YOU LOVE MOST IN THE WORLD! You gain a +1 to your highest stat, and cannot be made to use **[Drag]**, become **[Inept]**, **[Tiered Down]** or **[Nerfed]** with this stat. If a trigger would render you **[Enthusiastic]** while you are **[Passionate]**, you gain **2 [Boost]**.\r\n'),
('brave', 'BRAVE', '**[Base][Opposite: Scared]**\r\nAn emotion where you feel ready for anything. It doesn\'t matter how big and bad the enemy is… you\'re gonna show them who\'s boss! When you use **[WHAM]** on a target, you gain **1 [Boost]** immediately.'),
('heroic', 'HEROIC', '**[Heightened][Opposite: Terrified]**\r\nAn emotion where you can take on the world! COME ON! WE CAN TAKE THEM DOWN! LET\'S DO OUR BEST! Taking damage while **[Heroic]** doesn’t make you lose **[WHAM]**. When you use **[WHAM]** on a target, you gain **1 [Boost]** immediately. If a trigger would render you **[Brave]** while you are **[Heroic]**, you gain **1 [WHAM]**.'),
('insightful', 'INSIGHTFUL', '**[Base][Opposite: Confused]**\r\nAn emotion where you think you understand exactly what\'s going on! You can\'t be made to use **[Drag]** on **[Mental]** or **[Psionic]** rolls.'),
('enlightened', 'ENLIGHTENED', '**[Heightened][Opposite: Dumbfounded]**\r\nAn emotion where EUREKA! You\'ve GOT IT! You can\'t be made to use **[Drag]** on **[Mental]** or **[Psionic]** rolls, and you have a **+1 [Buff]** to each! If a trigger would render you **[Insightful]** while you are **[Enlightened]**, you gain **2 [Boost]**.'),
('happy', 'HAPPY', '**[Base][Opposite: Sad]**\r\nAn emotion where you feel pretty good! When someone would give you a **[Negative]** emotion, they need to roll 1d8; on an odd number, they don\'t, and you just take **1 [Drag]**. Grey skies are all gonna clear up!~'),
('joy', 'JOY', '**[Heightened][Opposite: Crying]**\r\nPut on a happy faaaace! An emotion where you just feel awesome! You get the effects of **[Happy]**, but when something gives you **[Drag]**, you must roll 1d8 too. On an odd number, you\'re just totally unaffected! If a trigger would render you **[Happy]** while you are **[Joyful]**, you gain **2 [Boost]**.\r\n'),
('serious', 'SERIOUS', '**[Base][Opposite: Giggling]**\r\nAn emotion where you\'re really on the ball. No goofing off today, gang, we\'re being SERIOUS. Whenever someone rolls a **[Chicanery]** move against you and gets an OK or lower, you gain **1 [Boost]**. Now\'s not the time to be so silly!'),
('deadSerious', 'DEAD SERIOUS', '**[Heightened][Opposite: Laughing]**\r\nAn emotion where you\'re not just serious. You\'re DEAD SERIOUS.  You get **2 [Boost]** whenever anyone even TRIES to roll **[Chicanery]** against you, as you assure yourself you\'re nowhere near that childish. If a trigger would render you **[Serious]** while you are **[Dead Serious]**, you gain **2 [Boost]**.'),
('tired', 'TIRED', '**[Base][Opposite: Enthusiastic]**\r\nAn Emotion where… where you… yaaaaawn… sorry! Sorry, you’re good. You’re great, even! Just… a lil sleeby… whenever you get a **GREAT** or higher roll, you take **1 [Drag]** as you overexert yourself, just a little bit.'),
('exhausted', 'EXHAUSTED', '**[Heightened][Opposite: Passionate]**\r\nHey… you’re kinda gripping onto consciousness here… oh, gosh, you just… god, it’s hard to… stay awake at all… whenever you get a **GOOD** or higher roll, you take **1 [Drag]**, and all **[Manipulate]** or **[Control]** rolls against you are **[Tiered Up]** as you find it difficult to focus on rational thought right now.  If a trigger would give you Tired while you are Exhausted, you fall **[Unconscious]** until someone wakes you up. Snzzz!'),
('scared', 'SCARED', '**[Base][Opposite: Brave]**\r\nAn Emotional condition where you’re on edge and afraid that something spooky’s gonna happen. Everything bad feels so much worse! When you would use **[Drag]**, you take an extra **-1 [Nerf]** to the roll as you freak out over it.'),
('terrified', 'TERRIFIED', '**[Heightened][Opposite: Heroic]**\r\nAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA!!!!!!! When you would gain **[Drag]**, you gain an additional **1 [Drag]**, and you have a **-1 [Nerf]** to **[Mental]** and **[Manipulate]** rolls. If a trigger would render you **[Scared]** while you are Terrified, you gain **2 [Drag]** (the bonus from the condition itself does not apply). '),
('sad', 'SAD', '**[Base][Opposite: Happy]**\r\nAn Emotional condition where you’re just kinda bummed out, man. Agh… you lose the effects of moves that make other rolls **[Inept]**, **[Nerfed]** or **[Tiered Down]** against you.\r\n'),
('crying', 'CRYING', '**[Heightened][Opposite: Joy]**\r\nWaaaahhh! Tears roll down your face, and the dams burst— you’re crying your eyes out. Your caste is revealed, and your moves that make other rolls **[Inept], [Nerfed]** or **[Tiered Down]** against you are disabled, giving such rolls a **+2 [Buff]**. If a trigger would render you **[Sad]** while you are Crying, you gain **2 [Drag]**. '),
('giggling', 'GIGGLING', '**[Base][Opposite: Sad]**\r\nHeehee! That’s a good one! You’re getting a little distracted, though. You are no longer able to use **[Lengthy]** moves while afflicted, and are **[Inept]** at **[Mental]** rolls.'),
('laughing', 'LAUGHING', '**[Heightened][Opposite: Crying]**\r\nWAHAHAHAHAHA! Oh, oh man, it’s actually really hard to stop laughing right now! Who knew too much **[Giggling]** was a bad thing?! You cannot perform any **[Lengthy]** actions, and your lowest stat (randomly selected if you have multiple) become **[Godawful]** in the process. Your **[Mental]** rolls are also **[Inept]**, potentially making them **[Godawful]**. If a trigger would render you **[Giggling]** while you are Laughing, you gain **2 [Drag]**. '),
('dread', 'DREAD', '**[Base][Opposite: Hopeful]**\r\nAn Emotional condition where you’re sure something bad is coming, on an existential level. Whenever you gain **[Boost]**, you gain 1 less, minimum 0. '),
('despair', 'DESPAIR', '**[Heightened][Opposite: Inspired]**\r\nAn Emotional condition where nothing even matters anymore. The end of times has come. Why are you even reading this? What’s the point? You cannot gain **[Boost]** in this condition. If a trigger would give you **[Dread]** while you are in Despair, you gain **2 [Drag]**.'),
('confused', 'CONFUSED', '**[Base][Opposite: Insightful]**\r\n...eh? Wait, huh? An Emotional condition where you’re… kind of unsure as to what’s going on. Any time you get a **BAD** or lower result from rolling, you are **[Stunned]**, because god, what?'),
('dumbfounded', 'DUMBFOUNDED', '**[Heightened][Opposite: Enlightened]**\r\nWhat in the whole fuck. Huh??? Wait, what?????? Can someone PLEASE tell you what’s going on?! When you get a BAD roll, you are **[Stunned]** and lose all **[Talents]** for **2 rounds** as you grapple with the situation. If a trigger would render you **[Confused]** while you are Dumbfounded, you gain **2 [Drag]**. '),
('disgusted', 'DISGUSTED', '**[Base][Opposite: Charmed]**\r\nEugh! Somebody get it away from you! You’re positively sickened by what you’re seeing. An Emotional condition where you feel positively sickened! If you **[Heal]**, you take **2 [Drag]** because BLEGH. BLEH… '),
('revolted', 'REVOLTED', '**[Heightened][Opposite: Fascinated]**\r\nABSOLUTELY DISGUSTING. GOOD GRUB, WHY. BLECH. BLEEECH. Whenever you **[Heal]**, you take **2 [Drag]** and are **[Stunned]** as you barely manage to keep yourself together. If a trigger would render you **[Disgusted]** while you are **[Revolted]**, you gain **2 [Drag]**.'),
('stressed', 'STRESSED', '**[Base][Opposite: Peaceful]**\r\nAn emotion where you... Nnnrgh. Fuck! Goddamit, fuck! Any time you get an **OK** or lower roll, you gain **1 [Drag]** as your frustration builds.'),
('agitated', 'AGITATED', '**[Heightened][Opposite: Serene]**\r\nAn emotion where FUCKING FUCK GODDAMMIT FUCK. NOTHING EVER GOES YOUR WAY, NNNRGH! You have a **-1 [Nerf]** to all rolls, and gain **2 [Drag]** on an **OK** or lower roll. If a trigger would render you **[Stressed]** while you are **[Agitated]**, you gain **2 [Drag]**.'),
('embarrassed', 'EMBARRASSED', '**[Base][Opposite: Proud/Smug]**\r\nAn Emotion where you can just FEEL the cringe coming off of you. Please, god, nobody look at you. You lose your Caste **[Talent]** as you doubt your own abilities. Huuuu…'),
('humiliated', 'HUMILIATED', '**[Heightened][Opposite: Icarian/Supercilious]**\r\nAn Emotion where you AAAAHHH GOD NOBODY EVER LOOK AT YOU AGAIN FUCK GOD THIS IS THE WORST FUUUUUCK. You become **[Inept]** at your Caste Talent. If a trigger would render you Embarrassed while you are Humiliated, you become **[Inept]** at your next highest stat.'),
('enraged', 'ENRAGED', '**[Base][Opposite: Focused]**\r\nAn emotion where you are AAAANGRY. MAD. SO MAD. GOTTA FIGHT. GOTTA SMOOSH. Your **[Strife]** and **[Physical]** rolls have a **+2 [Buff]**, but all your other rolls have a **-2 [Nerf]**. '),
('outOfControl', 'OUT OF CONTROL', '**[Heightened][Opposite: Hyperfocused]**\r\nAn emotion where you’re RRRAAAAAAAAAAARGH! ANGER! HATRED! KIIILL! You’re on a RAMPAGE! Your **[Physical]** and **[Strife]** rolls are **[Tiered Up]**, all your other rolls are **[Tiered Down]**, and **[Control]** rolls against you are **[Tiered Up]**. Don’t let your anger consume you! If a trigger would render you **[Enraged]** while you are Out Of Control, you gain **1 [WHAM]**. \r\n'),
('focused', 'FOCUSED', '**[Base][Opposite: Enraged]**\r\nAn Emotion where you. Are. so. Focused. Right. Now. All your **[Mental]**, **[Psionic]**, and **[Magic]** rolls gain a **+2 [Buff]**, but all of your **[Physical]** rolls gain a **-2 [Nerf]** because haha, you have weak nerdy noodle arms. '),
('hyperfocused', 'HYPERFOCUSED', '**[Heightened][Opposite: Out of Control]**\r\nDon’t talk to me, I’m in my mind palace. An Emotion where all of your **[Mental]**, **[Psionic]**, and **[Magic]** rolls are **[Tiered Up]**, but all of your **[Physical]** rolls are **[Tiered Down]** as your enormous studly brain meat eats all your energy. If a trigger would render you **[Focused]** while already Hyperfocused, you gain a **+1 [Buff]** to your next **[Mental]** roll. '),
('numb', 'NUMB', '**[Base][Opposite: Enthusiastic]**\r\n(Just imagine lines upon lines of ellipses and blank eyes. That’s the flavour text, here). While **[Numb]**, you cannot receive any new Emotion effects. You’ve just… had a long day. '),
('disassociating', 'DISASSOCIATING', '**[Heightened][Opposite: Passionate]**\r\nYou can\'t fucking exist right now come back later. As well as the above, you become impervious to the effects of **[Drag]**, but also cannot use **[Boost]**. You lose all other Emotions. Your **[Tier Ups]** and **[Tier Downs]** no longer affect you. If a trigger makes you **[Numb]** while you’re **[Dissociating]**, you are **[Stunned]**.'),
('charmed', 'CHARMED', '**[Base][Opposite: Disgusted]**\r\nAww! An Emotional condition where you’ve taken a shine to someone. What a little rascal! Your **[Strife]** rolls against the target are **[Inept]**, and whenever they gain **[Boost]**, you gain 1 too.'),
('fascinated', 'FASCINATED', '**[Heightened][Opposite: Revolted]**\r\nGoodness gracious! You love this little guy! What a cool and interesting person, you wanna be their friend! Your **[Strife]** rolls against the target are **[Godawful]**, whenever they gain **[Boost]** you do too, and whenever they gain a positive emotion, you do too. If a trigger would render you **[Charmed]** while you are Fascinated, you gain **1 [Boost]**.'),
('proud', 'PROUD', '**[Base][Opposite: Embarrassed]**\r\nAn emotion where you\'re a little too confident in your abilities! All your **GOOD +HUB** rolls are **[Tiered Up]** to **GREAT**, but all your **OK +HUB** rolls are **[Tiered Down]** to **BAD**.'),
('icarian', 'ICARIAN', '**[Heightened][Opposite: Humiliated]**\r\nHAHAHAHA! AND WITH THESE WAXY WINGS, YOU SHALL FLY DIRECTLY INTO THE SUN. HAHAHAH- OH NO! All your **GREAT +HUB** rolls are **[Tiered Up]** to a **MAX**, but all other **+HUB** rolls are **[Tiered Down]** to a **MIN**. Ruh-roh! If a trigger would render you **[Proud]** while you are **[Icarian]**, you gain **2 [Boost]**.'),
('overwhelmed', 'OVERWHELMED', '**[Base][Opposite: Tired]** \r\nAn Emotion where HNRRRR so much is happening, fuck. Before you use a rolled move, roll 1d8; on a 1-2, the move is **[Inept]**.'),
('sensoryOverload', 'SENSORY OVERLOAD', '**[Heightened][Opposite: Exhausted]**\r\nAn Emotion where ZZZKZKKTTKKZZZ YOU CAN FEEL YOUR SKIN YOU CAN FEEL EVERYTHING IT’S TOO BRIGHT IT’S TOO LOUD THE CHEESEBURGER YOU ATE EARLIER IS LIKE POISON ON YOUR TONGUE, AAAARGH. Before you use a rolled move, roll 1d8; on a 1-2, the move is **[Godawful]**. If a trigger would make you Overwhelmed while you have Sensory Overload, you gain **2 [Drag]**. ');
INSERT INTO `hazard` (`key`, `title`, `tags`, `text`) VALUES
('angryMob', 'ANGRY MOB', '[Physical]\r\n', 'Rabble rabble rabble... The crowds’ rabbles have been roused, and they\'re about to riot pretty fucking hard! \r\n\r\n> **FIRST ROUND**: Dissenting murmurs tip you off that the crowd isn\'t happy. The crowd selects targets based on whatever triggered the **[Hazard]** to form. This may disclude certain characters in the encounter. All selected targets take **2 [Drag]**.\r\n\r\n> **SECOND ROUND**: Oh, they\'re starting to shout now! Targets who are not **[Hidden]** take **1 [Verbal]** and **1 [Somatic]** damage each turn. The Clouder or whoever is controlling the Mob can decide to activate **[Drag]**, and can seek you out if you are **[Hidden]** with a **+4 [Analyze]** roll for **[Free]**. In lieu of hiding from the mob, you may choose to fight it; an ANGRY MOB has 10 HP and is immune to status effects. This round repeats until the mob is unable to find a troll on their turn.\r\n\r\n> **THIRD ROUND**: The Mob mills around, grunting and doing property damage in frustration. They make another **[Analyze]** roll to seek out **[Hidden]** trolls, this time with a +1 roll as they tire of looking. Any items, Vehicles or similar left out take **3 [Somatic]** damage. If a troll reveals themselves or is forcibly revealed by another troll (for example, a successful **[Analyze]** by a non-targeted troll), the **[Hazard]** resets to Round 2.\r\n\r\n> **FOURTH ROUND**: The crowd disperses, pretty annoyed. The Mob breaks up. Obvious attempts to get the crowds’ attention by targeted trolls in the next **3 rounds** resets the **[Hazard]** to **Round 1**; otherwise, the **[Hazard]** ends.\r\n'),
('beeSwarm', 'BEE SWARM', '[Physical]\r\n', 'What is it? What is it? What is that, what is that, what is it? Oh no, not the bees! Not the bees! Aaaaah! Your eyes! Your eyes! Aaaaah! A bee swarm is here and ready to fuck your shit up. And oh boy, it\'s gonna fuck you up HARD.\r\n\r\n> **FIRST ROUND**: Do you hear that? That ominous buzzing? What? What is that? All trolls in the area become **[Confused]**.\r\n\r\n> **SECOND ROUND**: BEES! OH, OH GOD, OH NO! AAAAARGH! All trolls not currently **[Hidden]** take **1 [Somatic]** damage. **[Hidden]** trolls can attempt to seek each other out with an **[Analyze]** roll, and push each other out with a GRIEF roll that does 1 less damage in order to push them into the open, where they\'ll take damage at the start of their next turn.\r\n\r\n> **THIRD ROUND**: The bees continue to sting anyone not currently **[Hidden]** and deal **1 [Somatic] damage**.\r\n\r\n> **FOURTH ROUND**: The bees disperse if there are no trolls not currently **[Hidden]**. They continue to sting if there are, and this continues til all trolls are **[Hidden]**. The **[Confused]** condition ends when all trolls are **[Hidden]**.\r\n'),
('droneStrike', 'DRONE STRIKE', '[Physical][Mental]\r\n', '[S] MAKE THEM PAY. Sirens wail, people scream. Drones, Alternia\'s vanguard is here to rain fire and fury on the guilty. And the innocent. Man, it\'s pretty fucked up, they\'ll just kill anyone, huh?\r\n\r\n> **FIRST ROUND**: The humming of drone engines and the wail of sirens strikes terror in your bloodpusher. All trolls gain the **[Scared]** condition.\r\n\r\n> **SECOND ROUND**: The Drones land, and chaos reigns. All living things not currently **[Hidden]** take **2 [Somatic]** damage that ignores **[Resistance]**. The Drones seek out hiding trolls with a **+2 [Talented] [Analyze]** roll as a **[Free]** action. If they find you, you take the damage immediately. You may also attempt to gain the **[Hidden]** condition by playing dead; roll SWASHBUCKLE. Getting a **GREAT** immediately makes you **[Hidden]**, and the Drones’ **[Analyze]** check is no longer **[Talented]**. Failing this makes you take the **[Bloodied]** condition, you dumb asshole, as they open fire on you. Moves that stun or halt **[Mechanical]** creatures make them jump forward a round. The **[Hazard]** has **12 HP** for every target troll present, and can technically be bested in combat with enough luck, but resisting the **[Hazard]** other than to **[Hide]** causes them to do **+1 damage** every round, stacking as it goes.\r\n\r\n> **THIRD ROUND**: The drones continue to open fire on anything that moves. BRAKABRAKABRAKA! Round 2 repeats.\r\n> **FOURTH ROUND**: God, they\'re determined, huh? Round 2 repeats.\r\n> **FIFTH ROUND**: Fuck, dude. Round 2 repeats.\r\n> **SIXTH ROUND**: Yyyyup. Still up there. Round 2 repeats.\r\n\r\n> **SEVENTH ROUND**: Alright, by now everyone is definitely dead. The Drones leave. Trolls still openly showing resistance take **5 [Somatic]** damage. If nobody took any damage during this drone strike, and nobody played dead, the FIRE!!! Hazard starts as they burn the location down with Incendiary Bombs. What a load of jerks!\r\n'),
('dimmingStars', 'DIMMING STARS', '[Magic][Mental]\r\n', 'Through the light pollution, industrial pollution and psychic pollution in the air, the stars of the galaxy above have never stopped shining down on Alternia every night. The dual moons have never abandoned you, have never left you alone in your sorrows. No matter your caste, your legality, who you are or what you\'ve done... the stars and the moons have been by your side through the best and worst of times; companions of unshakable loyalty. Something terrible has blotted them out of the skies. A **MAX +IMG** check will push back the hazard a stage and a second will dispel it. Alternatively, three **GREAT [Magic] +IMG** checks without any **GOOD**s or lower breaking the chain by a troll possessing **[Magic]** will also work for dispelling it. **[Drag]** is automatically used on these **[Magic]** checks if it is able to lower the result below a **GREAT**. **[Magic]** excludes **[Zodiac]** moves for this Hazard.\r\n\r\n> **FIRST ROUND**: The stars dim, and only the radiant pink and green lights in the sky can be easily seen. Something is wrong. All trolls possessing **[Magic]** gain **2 [Drag]** as they feel something... change in the air around them.\r\n\r\n> **SECOND ROUND**: The pink light has faded, and with it goes the stars. With only the Green Moon left to watch over you, something terrible approaches. All trolls possessing **[Magic]** gain **2 [Drag]** and all others gain **1 [Drag]**. **[Magic]** rolls are **[Inept]**.\r\n\r\n> **THIRD ROUND**: Can you see it? The last glimmers of green giving way to the blackness of... not space, but something... else? All **[Magic]** possessing trolls take **3 [Drag]** and become **[Scared]**, all other trolls gain **3 [Drag]**.\r\n\r\n> **FOURTH ROUND**: The sky is empty. All trolls gain **5 [Drag]**, and all **[Magic]** is blocked. Additionally, all trolls become **[Trapped]** by… a presence of sorts. Something has taken the above from you. \r\n\r\n> **FIFTH ROUND**: Can you feel it? The empty abyss above watching you with a thousand timeless eyes? All trolls become **[Terrified]** even if they would normally be immune, and any trolls who possess **[Magic]** take **2 [Psychic]** damage. Grimdark trolls do not take these effects and instead have all **[Drag]** wiped, gaining **5 [Boost]**, or gaining **3 HP** instead if they have crossed the EVENT HORIZON. \r\n\r\n> **SIXTH ROUND**: The fifth round repeats indefinitely until dispelled or all trolls are **[Unconscious]**, Grimdark or dead, upon which it moves to the seventh round. Run.\r\n\r\n> **SEVENTH ROUND**: It was all just a bad dream…! The **[Hazard]** ends, and most definitely never happened. Right…? Calm down and relax… the stars will always be here for you.\r\n'),
('daytime', 'DAYTIME', '[Physical]', 'It’s hot out here. It’s not just you. It’s the daytime and you are in for a world of pain if you don’t get inside or under shelter soon! Rainbow Drinkers, Shadowdroppers and trolls with the SUN TOUCHED jade move are immune to the effects of the sun.\r\n\r\n> **FIRST ROUND**: Ouch— OUCH! You’re **[Blinded]**! It’s hard to see. Better get running for cover! This effect wears off if you find shelter.\r\n\r\n> **SECOND ROUND**: Oh, god, you’re starting to bake alive. You take **1 [Unblockable] [Blaze] [Somatic]** damage; if you’re a seadweller, you take 2. Tempura shrimp!\r\n\r\n> **THIRD ROUND**: Gahhhhh! Every consecutive turn you spend in the sunlight, your skin starts to crack and you take **2 [Unblockable] [Blaze] [Somatic]** damage because you are, quite literally, baking under this intense heat! You may become **[Permablind]** forever if you so choose; and you become **[Ablaze]** and cannot put it out until you find shelter.\r\n'),
('flood', 'FLOOD', '[Physical]\r\n', 'Water... the stuff of life, and sometimes of death. Whether it’s an overflowing river, a capsized ship, or a few too many zeros at the end of your latest Faygo shipment, unless you can get to high ground soon you’re about to be in for a world of hurt. Violet trolls are immune to this hazard, naturally.\r\n\r\n> **FIRST ROUND**: A torrent fills the area, or you’re dunked unceremoniously into one, struggling for footing or even just to float. You’re **[Slowed]** - moving around in deep water is as hard as it looks!\r\n\r\n> **SECOND ROUND**: Now that you’re in the water, the tide threatens to knock you over, sealing your fate. Roll 1d4 - that many affected trolls, chosen at random, are knocked **[Floorbound]** by the raging current, ignoring immunities or replacement effects and the usual one-round cooldown even if they would normally be applicable.\r\n\r\n> **THIRD ROUND**: As the currents rush over you, losing your footing for even a second or being pulled under the waves could spell death. The effects of the second round repeat, and all **[Floorbound]** trolls are now immediately subjected to the DROWNING **[Affliction]**.'),
('fire', 'FIRE!', '[Physical]\r\n', 'Aaaaaargh! Fire, fire! Maybe it’s a forest fire— maybe your home is ablaze! One way or another, you’re dealing with fire! FIRE, GODDAMMIT! As you stay in the fire, shit starts to go horribly bad. \r\n\r\n> **FIRST ROUND**: Cough, cough! The smoke in here is thick— you take **2 [Drag]**! Your PROBLEM SLEUTHING rolls are **[Inept]**; it’s hard to see anything with all of it.\r\n\r\n> **SECOND ROUND**: Oh, god, it’s really hot… and hazy… cough, cough… you take **2 [Drag]**, **1 [Blaze] [Somatic] damage**, and your PROBLEM SLEUTHING rolls are **[Godawful]** as smoke inhalation clouds your mind. You’re exposed to the CHOKING **[Affliction]** and are **[Inept]** on rolls against it.\r\n\r\n> **THIRD ROUND**: OH GOD, NOW YOU’RE ON FIRE! YOU’RE VERY MUCH SO AWAKE NOW! AAAAA! FUUUUCK! You’re **[Ablaze]**, and can’t be put out until you’re out of the fire. The damage you take from being **[Ablaze]** increases by 1 each turn; spend more than **5 rounds** like this, and you’re probably going to get some permanent scarring and **1 [Blaze] [Weakness]**.'),
('paranormalActivity', 'PARANORMAL ACTIVITY', '[Psionic][Mental]\r\n', 'Whoooaaaahhhh! This ain\'t no lame haunting! This is ADVANCED spookiness! Hordes of phantoms rock up on the living, intent to bring you to join their phantasmagoric fever!\r\n\r\n> **FIRST ROUND**: Doors start to lock, lights start to flicker, and the earth starts to shake. Trolls without the **[Eerie]** tag are **[Scared]** and **[Trapped]**.\r\n\r\n> **SECOND ROUND**: WHHHOOOOAAAAHHHH! Phantoms apparate, causing a lot of fear to all those around! Non-SCP trolls without the **[Eerie]** tag become **[Terrified]**. Any troll who gets a BAD or below on any **+IMG** roll takes **1 [Psychic]** damage.\r\n\r\n> **THIRD ROUND**: Poltergeistic happenings overwhelm everyone present! Any troll who gets a **GOOD** or below on any **+IMG** roll takes **1 [Psychic]** damage. Every round, the clouder rolls 1d8 to determine a random haunting activity which affects a troll present.\r\n\r\n> 1. The ghosts toss you around! You become **[Floorbound]**. \r\n> 2. Ready or not! All affected trolls are **[Blinded]** for a round as thick mists obscure the area.\r\n> 3. Poltergeists at their most iconic. A random item is removed from your Sylladex and spat across the room. You can only add it back with a successful Yoink action.\r\n> 4. FREEZE! Ice cold temperatures make you **[Godawful]** at **[Physical]** rolls for a round.\r\n> 5. Murmur murmur... Affected trolls take **2 [Drag]**.\r\n> 6. PCHEWWWW! The ghosts fly around with you! You start **[Flying]** for a turn.\r\n> 7. Possessed! Your opponent rolls with your moves and stats for a round! This affects the possessed troll like a **GOOD** roll of the Ghost POSSESSION move.\r\n> 8. DOUBLE DEATH! Roll twice and take both options. This stacks indefinitely if you keep rolling 8s til you have every option.\r\n\r\n> **FOURTH ROUND**: Repeat round 3 ad infinitum. \r\n'),
('rainstorm', 'RAINSTORM', '[Physical]\r\n', 'Uh oh… you didn’t pay enough attention to the weather and you got caught out in the rain without your industrial strength umbrella! The rain of Alternia is highly acidic, and standing out in it for too long starts to burn your skin. That’s going to sting! The longer you spend out in the rain, the worse it’s going to feel.\r\n\r\n> **FIRST ROUND**: You take a **2 [Drag]** because… that stinging sensation is really getting to you.\r\n\r\n> **SECOND ROUND**: Ouch! Ouch, you say! You take **4 [Drag]**, and your **[Mental]** rolls are **[Inept]**, since you can’t really concentrate right now.\r\n\r\n> **THIRD ROUND**: You take **2 [Somatic] damage**. You’re really starting to feel it! Your **[Mental]** rolls are **[Godawful]**, because holy fuck, it hurts. Every turn after this point, you continue taking **1 [Somatic] damage** until you find shelter. Once you get out of the rain, you stop taking damage per turn, but the **[Ineptitude]** or **[Godawfulness]** stays until you find a way to clean it off! Because it still stings and you’re covered in acid! '),
('rocksFall', 'ROCKS FALL', '[Physical]\r\n', 'You die. Okay, maybe not yet, but rocks falling is never a good thing! Maybe it’s a cave-in, maybe it’s a landslide, maybe it’s the building you’re in collapsing— no matter what, you want to get out of there, fast!\r\n\r\n> **FIRST ROUND**: You hear a loud rumble, and your stomach drops. Ah, shit. You’re **[Scared]**, and you take **1 [Drag]**.\r\n\r\n> **SECOND ROUND**: Everything starts collapsing around you! You need to try to Abscond, but the building is going to roll Can’t Abscond Bro as obstacles fall in your way. It’s **[Talented]**, and has a **+2 modifier**.\r\n\r\n> **THIRD ROUND**: Rocks fall, you die. You take **4 [Somatic] damage**, can’t use **[Physical]** rolls, and are **[Slowed]** and take **1 [Unblockable] [Somatic] damage** at the start of each of your turns until freed. You’re also **[Hidden]**; your friends (if there are any there) must roll PROBLEM SLEUTHING to find you, and then get at least a **GREAT +GRT** roll as an action to shove the rocks off you.'),
('realityCrack', 'REALITY CRACK\r\n', '[Mental][Magic]\r\n', 'Ever the investigative scamp you are, you’ve stumbled upon something you really mustn\'t see! Whether it be one of the illustrious few remaining candy horrors in the world, being frowned upon by the smirkbarons of the wandering jesterwilds, or just eating the wrong candy, you’ve snap crackle popped something in the very reality around you.\r\n\r\n> **FIRST ROUND**: The sky cracks with an ethereal sound, it’s reminiscent of an icy lakebed thawing after a long winter. If you were to look hard enough, you may see splinters of reality itself, and you feel a strong sense of **[Dread]** coming over you at the mere sight of these splinters.\r\n\r\n> **SECOND ROUND**: Some invisible force pushes through- you’d think there to be some sort of indication, but all you get is a face full of... Snow. The particulate of this glass-looking crack, in reality, is not quite so, as there’s now non-acidic, candy-flavored snow falling from the cracks. You may now begin making **+GRT** rolls to avoid ingesting it.\r\n\r\n> **THIRD ROUND**: As the now catastrophic amount of candy-snow is piling out, your **[Dread]** turns to **[Laughter]** and you become **[Clumsy]** as your dumb ass is distracted. All Tricksters have a +1 to their rolls against non-tricksters this round, as the excitement builds. \r\n\r\n> **FOURTH ROUND**: Whether you stuck out your tongue and accepted your new candy overlords, or fought with every last bated breath, you’ve reached the end of the line and are now infected with the TRICKSTER’S GAMBIT AFFLICTION.\r\n'),
('stampede', 'STAMPEDE', '[Physical]\r\n', 'What is the number one reason for a day off work on Alternia? Oh please let me tell yo-LUSUS ATTACK. LUSUS ATTACK. [Flashing Images of destruction caused by lusii] LUSUS ATTACK. LUSUS ATTACK [Flashing images of young trolls in peril at the behest of lusii] It\'s a lusus attack! Whether it\'s multiple small lusii running wild or one big one charging through, you do not want to forget your survival training when messing with these guys. \r\n\r\n> **FIRST ROUND**: Tremors shake the ground. Trolls must make a **GOOD +GRA** roll or be knocked **[Floorbound]**. If the cause of the **[Hazard]** was already in the encounter (for example, if you ran up to a pack of Screamus and spanked one hard), skip to Round 2.\r\n\r\n> **SECOND ROUND**: TAKE COVERRRR! Trolls without the **[Hidden]** condition take **2 [Somatic] damage** and get knocked **[Floorbound]**. Trolls that were already **[Floorbound]** take an additional **1 [Somatic] damage**. **+HUB** rolls during this round are **[Inept]**, but getting a **GOOD** roll gives you **2 [Boost]**. Failing throws you **[Floorbound]** and lets you take damage for this round. \r\n\r\n> **THIRD ROUND**: STOMPSTOMPSTOMPSTOMPSTOMPSTOMPSTOMP! The effects of Round 2 repeat.\r\n\r\n> **FOURTH ROUND**: The Stampede ends, leaving a trail of destruction in its wake. Trolls who wish to follow the STAMPEDE at a distance may do so with a successful **[Analyze]** roll to track them, if that\'s important to the plot or whatever.'),
('screegullSwarm', 'SCREEGULL SWARM', '[Physical]\r\n', 'Birds of prey come in all shapes and sizes but none are more ruthless or bloodthirsty then the screegull itself, with its two heads, four wings, flamethrower breath, and propensity for stealing your French fries. Unlike most hazards, screegull swarms can be satiated temporarily whenever a **[CONSUMABLE]** item is sacrificed for them to gorge upon. When food is given up the screeagull swarm resets back one stage, the timer resetting in the process. Each time the swarm isn’t fed, they progress one round. \r\n\r\n> **FIRST ROUND**: THE SCREEGULLS ARE HERE THE SCREEGULLS ARE HERE !! AND THEY ARE HUNGRY !! Everyone in the encounter takes **1 [Drag]** as the birds flap around looking for a meal. \r\n\r\n> **2 ROUNDS WITHOUT EATING**: You absolute buffoon. You chicanerous fiend. You didn\'t feed the gulls and now they\'re angry. The gulls peck at everyone in the encounter, scrounge through backpacks, and make nests in hair. (Bald people are immune to this part of the hazard). All items and specibi are knocked out of everyone\'s hands and sylladex items cannot be pulled out without immediately being thrown to the ground. Picking up an item costs an action.\r\n\r\n> **5 ROUNDS WITHOUT EATING**: Lord almighty you\'ve fucking done it. The seagulls are starved and have decided to go for flesh. In addition to all the above instances everyone in the encounter takes **2 [Somatic] damage** every round. It\'s horrible, they\'re trying to eat you alive.\r\n'),
('snowstorm', 'SNOWSTORM', '[Physical]\r\n', 'This effect is a double whammy. For one thing, it’s fucking COLD. For another, the snow on Alternia is ALSO acidic. Yaaay! Though the acid is not quite as potent as in the rain, the cold could be the end of you if you’re not careful.\r\n\r\n> **FIRST ROUND**: Nooksludge, it’s fucking cold! You should have worn some warmer clothes! You take **2 [Drag]** as you shiver.\r\n\r\n> **SECOND ROUND**: Brr… brrrrr… You take another **2 [Drag]**, and you are **[Slowed]**. Must… get… to safety…\r\n\r\n> **THIRD ROUND**: The snow cakes into you, and it begins to burn! You take **1 damage** and **2 [Drag]** now, and another **1 damage** and **2 [Drag]** for **every turn** you stay in the snow. If more than **5 turns** pass, you fall **[Unconscious]**. ');
INSERT INTO `hivecrafting` (`key`, `title`, `cost`, `text`) VALUES
('ablutionCavern', 'ABLUTION CAVERN\r\n', 3, 'This room is where you go to clean up, wash your hair, or otherwise refresh yourself. Complete with an Ablutiontrap, a Loadgaper, and some BEAUTIFUL tiled floors, your Ablution Cavern is perfect for making you feel like less of a fucking slob. When you spend a day of **[Downtime]** cleaning and washing in your Ablution Cavern, you look absolutely flawless. You gain access to the SPA DAY **[Downtime]** move. When you want to clean up and make yourself look gorgeous, roll **+PLC**.\r\n\r\n> **MIN**: You look like a fucking idiot, and you don’t even realize it. Seriously, you look like you heard about drag makeup, and decided “hey, I could do that!”, and then tried it without ever looking up how it works. All your **+PLC** rolls **[Tier Down]** for your next encounter.\r\n\r\n**BAD**: It doesn’t look great, but at least you catch yourself before you go out in public like this.\r\n\r\n> **OK**: You’re… cute. That’s all there is to say on the matter. You gain **1 [Hold]** for your next encounter; you can use this **[Hold]** to give yourself a **+1 [Buff]** to any one **+PLC** roll for **[Free]**.\r\n\r\n> **GOOD**: You take real good care of your skin! You feel **[Happy]** during your next encounter.\r\n\r\n> **GREAT**: Is that Rainbow Drinker Serum? Daaamn, expensive tastes, baby! You feel [Happy] during your next encounter, and can spend an action to feel **[Joy]** for **2 turns** before returning to **[Happy]**.\r\n\r\n> **MAX**: Oh, holy shit, you used the whole Rainbow Drinker Serum bottle. Like, the whole thing. You’re literally glowing, you’re that gorgeous. What the fuck. I have to bow, I’m literally bowing as I type this. You feel **[Joy]** during your next encounter.\r\n'),
('bookhive', 'BOOK-HIVE', 3, 'You have an impressive array of books at your disposal in your very own home, making research easy as pie! You gain the HIT THE BOOKS **[Downtime]** roll. When you want to study hard, roll **+PSP**.\r\n\r\n> **MIN**: Hrrnnnnhhnhnnhhh books hard… hhrhhhrhrhrhrhh… you’re particularly drowsy. You start your next encounter **[Exhausted]**.\r\n\r\n> **BAD**: This shit makes NO sense, no matter how hard you try! You learn nothing.\r\n\r\n> **OK**: You… might have learned something? Maybe? You gain 1 [Hold] that lasts a week; you can use this **[Hold]** before rolling to give yourself a **+1 [Buff]** to any one **[Analyze]** roll.\r\n\r\n> **GOOD**: You’ve prepared yourself well. Academia! Yay! You start your next encounter **[Focused]**.\r\n\r\n> **GREAT**: Intense study! You little mathlete, you! You start your next encounter **[Focused]**, and can spend an action to become **[Hyperfocused]** for **2 turns**.\r\n\r\n> **MAX**: I THINK THEREFORE I AM THEREFORE I THINK THEREFORE I AM THEREFORE E I PI EQUALS NEGATIVE FOUR A SQUARED PLUS B SQUARED EQUALS C SQUARED FOURTEEN-NINETY-TWO FIVE-NINETY-FOUR TEN-SIXTY-SIX BECAUSE I COULD STOP FOR DEATH HE KINDLY STOPPED FOR ME. You start your next encounter **[Hyperfocused]**.\r\n'),
('businessfront', 'BUSINESSFRONT', 3, 'Trolls don’t NEED to work; after all, they’re just kids! But some trolls run their own small businesses from their hive in an effort to gain more cash. Your MONEYMAKERY rolls have a **+2 [Buff]**, but ne\'er-do-wells could steal Treasure II from you and drop your Wealth Level by 1 if you lose a fight at hive, or they otherwise sneak in and steal from you (usually requiring them to make **3 YOINK** rolls while **[Hidden]** without being observed as a **[Downtime]** action. Hope you have the Security System!).\r\n'),
('securitySystem', 'SECURITY SYSTEM', 2, 'STAY OUT, INTRUDERS! Whether it\'s armed guards, cameras or your lusus now being specially trained, you\'re keeping your hive safe from bad guys. Your Hive automatically rolls **[Talented]** SPOT rolls with a **+2 modifier** on any trolls who attempt to enter it. If it finds someone, it makes a loud noise, making the troll **[Agitated]**. You become aware of the problem; it usually takes you 1d8-4 (min. 1) turns to get there. For an extra **3 LUX**, you can summon an ANGRY MOB, STAMPEDE, PARANORMAL ACTIVITY or DRONE STRIKE to the site. You can also hook your security system to specific items that people might be interested in stealing or attacking with a BASH-N-RUN, like a BUSINESSFRONT or a STORAGEPIT. How your Security System works is up to you, but make sure you write it down, so would-be intruders can find out information with a PROBLEM SLEUTHING roll and potentially RP entering your hive on their own. Without this upgrade, nothing is stopping them!\r\n'),
('hiveGym', 'HIVE GYM', 3, 'WEIGHTS. PUNCHING BAGS. SQUATS. GET SWOOOOLE FROM THE COMFORT OF YOUR OWN HIVE. You have your own little gym, and you’ve custom fit it to fit your own workout routine. You gain access to the GET RIIIIIIIIPPED **[Downtime]** move. When you wanna get buff, roll **+GRT**.\r\n\r\n> **MIN**: SPRAIN! You fuck yourself up with an irresponsible workout routine! Why did you do that? You start your next encounter **[Agitated]**.\r\n\r\n> **BAD**: You forget to actually go work out and spend the whole day just thinking about working out.\r\n\r\n> **OK**: You get STRONG. You get BUFF. You get… an okay workout. You do a few sit ups, if that counts. You gain **1 [Hold]** that lasts a week; you can use this **[Hold]** before rolling to add a **+1 [Buff]** to any **[Physical]** roll.\r\n\r\n> **GOOD**: Okay, THIS TIME you actually get STRONG and BUFF. Hooray! You start your next encounter **[Enraged]**.\r\n\r\n> **GREAT**: You’re so fucking strong; your MUSCLES have muscles. Damn! You start your next encounter **[Enraged]**, and can spend an action to go **[Out of Control]** for **2 turns**.\r\n\r\n> **MAX**: HRRRNRNNNNHHHH. MMMMUUUUSCCCLLLLE. SSTTTRRRROOOOONG. YYYOOOOU… BIG TROLL… THEM… PUNY! You start your next encounter **[Out of Control]**.\r\n'),
('mealblock', 'MEALBLOCK', 3, 'Mmmmm! Yuuuuuummy! You love a good meal, mmm-mmm-mmm! You cook up some food that isn\'t basically just food-shaped plastic here, and gain access to the MUNCHQUEST **[Downtime]** roll. When you wanna munch, roll **+APP**.\r\n\r\n> **MIN**: Huuuuu… your poor tummy… you ate too much… if you roll a **BAD** roll during your next encounter, ignore the regular results; instead, you become **[Poisoned]** as your meal comes back to haunt you.\r\n\r\n> **BAD**: This meal sucked. Didn\'t sit well with you or something. You start with **1 [Drag]** in your next encounter.\r\n\r\n> **OK**: This meal really wasn\'t anything to write home about. Kinda bland?\r\n\r\n> **GOOD**: Yum! It wasn’t filling, but it was nice! You gain **1 extra HP** during your next encounter.\r\n\r\n> **GREAT**: Deeeeelicious! You gain **+2 HP** during your next encounter. \r\n\r\n> **MAX**: That was absolutely WONDERFUL! 10/10 meal. 5 stars! You gain **+3 HP** during your next encounter.\r\n'),
('panicChamber', 'PANIC CHAMBER', 3, 'AAAAAAAAAAAAAAAAAAAAAAAA!!! When shit gets scary, it’s good to have a Panic Chamber! It’s filled with guides on “HOW TO SURVIVE THE END OF THE WORLD” or “THE GREMLINS ARE COMING: ALIEN SURVIVAL GUIDE”, so it’s safe to say you’re prepared for the worst. The first time in a week you would roll a **MIN** roll on a **[Downtime]** event, you start screaming and run hive so you can dive into your Panic Chamber. Phew! Crisis averted! You only get a **BAD** result instead.\r\n'),
('slitherBasin', 'SLITHER BASIN', 1, 'Aw, sweet, you’ve got a pool! Or maybe this is a bathtub? Surely it\'s not just a crater of water in your hive, right? While in your hive, any troll can spend an action to jump into your SLITHER BASIN, becoming immune to moves that do **[Fire]** damage, or **[Ablaze]** effects for **3 turns**, but becoming **[Soggy]** in the process. \r\n'),
('storagePit', 'STORAGE PIT', 1, 'Tired of throwing items away when you don\'t have enough VP in your Sylladex for them anymore? Put them away, instead! Sometimes, you just need a good ol’ fashioned hole to store shit in. It might be fancy, with different categories for different items, or robot arms to retrieve stuff for you— or it might just be an actual hole covered by a trapdoor in the corner of your respiteblock. Either way, you can store items in here; you get **3 VP** worth of stuff you can store in your STORAGEPIT. Removing them is a **[Lengthy]** action that can be done by anyone. Hope you\'ve got a Security System! Every **1 LUX** you spend increases your STORAGEPIT\'s capacity by 3. If the STORAGEPIT is somehow destroyed, everything inside it is harmlessly destroyed as well. Hope you didn\'t add this to a buggy!\r\n'),
('rumpusblock', 'RUMPUSBLOCK', 2, 'Alright bros, are you ready? It\'s time for the one, the only, GameBro! He\'s coming to your screen straight from the magazine. The mix meister of Master Swords and mushrooms. Are you sure you\'re ready for this? Well come on, get ready, get set, and here we go! You’ve converted a room into a Gamecave, just for you! There’s multiple screens, a swivel chair, maybe some black mold growing behind your setup if you didn’t pay enough… but one way or another, this is the perfect way to put in some hard earned GAME TIME climbing the ranks. You gain the VIDYAGAMEZ **[Downtime]** activity. When you want to spend time honing your EPIC GAMING powers, roll **+HUB**. \r\n\r\n> **MIN**: Through a series of rage quitting and angry flailing, you destroy your game console. You’ll need to spend **1 LUX** to buy a new console before using this roll again.\r\n\r\n> **BAD**: God, you really suck at Troll Just Dance, don’t you? \r\n\r\n> **OK**: You don’t make much progress in your skills, but hey, practice makes perfect, right? You gain **1 GAMER POINT**.\r\n\r\n> **GOOD**: Awww yeah! Epic Gamer Moment! You climb the ranks! You escort the payload! You shoot the plumbers! You get some REAL wins today, and gain **2 GAMER POINTS** as you gain notoriety in the community. \r\n\r\n> **GREAT**: Damn, bitch! You won a minor tournament! You win a number of Treasure equal to half of the amount of **GAMER POINTS** you have accumulated, rounded up. Your **GAMER POINTS** reset to 0. If you have no **GAMER POINTS**, you win **Treasure I**; it wasn’t that big a tournament.\r\n\r\n> **MAX**: OH MY GOD! OH MY GOD! YOU DID IT! YOU BEAT TROLL FLAPPY BIRD! HOLY SHIT! A NEW WORLD RECORD! You’re overwhelmed with sponsorships and prize money, and win Treasure equal to 2 x the amounts of **GAMER POINTS** you had accumulated. If you had no **GAMER POINTS**, you win **Treasure II**. Your **GAMER POINTS** then reset to 0.\r\n'),
('dangerousStructure', 'DANGEROUS STRUCTURE', 1, 'Careful… CAREFUL… your Hive is a little… ramshackle at times. At the start of every new round during a combat encounter in your hive, roll 1d8. On a 1, uh oh! A random **[Hazard]** happens! Shoot!\r\n'),
('thematicFurniture', 'THEMATIC FURNITURE', 2, 'Hmmm… you\'re definitely going for a certain vibe here, aren\'t you? It\'s like you really, really want people to know that a pirate or doctor or whatever lives here. While in your hive, you are **[Talented]** at all rolls you have gained through **[Templates]**, but all trolls **[Analyze]** rolls against you are also **[Talented]**.\r\n'),
('teleTv', 'TELE-TV', 2, 'This big, biotech TV means you\'re able to watch the news easily! You can flick on your TV as an action; while on, no troll\'s negative **[Emotions]** can be Heightened. Soothing, comforting TV…\r\n'),
('premiumLoadgaper', 'PREMIUM LOADGAPER', 2, 'This… this is a toilet. You use it when your body needs you to. Trolls present in your hive can spend a **[Lengthy]** action in this room to remove the **[Poisoned], [Disgusted]** and **[Revolted]** conditions. Much better!\r\n'),
('littleGarden', 'LITTLE GARDEN', 3, 'How quaint! In this garden, you can grow your own plants. These generally function as **[Consumable]** items you have access to, except that they cost **1 VP** extra, and using them removes a **[Physical]** condition from you. If the item is THE GOOD SHIT or some variant, your rolls against the INEBRIATION **[Affliction]** are **[Godawful]**. Grow some sugarcane for your homemade energy drinks, fuck it! Watch out though… if someone steals an item from your LITTLE GARDEN, they pay **2 VP** less than normal (min. 1), and you can\'t use your LITTLE GARDEN until you spend **2 LUX** fixing it!\r\n'),
('spiritualShrine', 'SPIRITUAL SHRINE', 3, 'Hmmm… whether it\'s a place to pray to the Messiahs, or an evil place for evil fucked up magic, this shrine helps you do things you couldn\'t normally do. If you spend a **[Lengthy]** action praying by this shrine, your next **[Magic]** roll is **[Legendary]**. Watch out though, cuz anyone can do it!\r\n'),
('thermalHull', 'THERMAL HULL', 2, 'Ostensibly, this cooling device shaped like a large cuboid is meant to cool food. Most of the time though, it\'s to trap people inside of, or to avoid nuclear blast. You can throw a troll into a THERMAL HULL with a **GREAT GRIEF** roll that does no damage. It takes an ABSCOND roll with a 17+ result to bust out. Trolls inside the THERMAL HULL can\'t interact with trolls outside of it at all, and take no damage ever, even from **[Unlockable]** sources. Beware, others can throw you in too, if you\'re not careful. \r\n'),
('flexpiece', 'FLEXPIECE', 10, 'WOW. What. A. BEAUTY. It\'s the coolest thing you\'ve ever seen, right? Yup… this obnoxious piece of decor really ties the whole hive together. Everyone probably loves it! While at hive, you can spend an action to become **[Smug]** and **[Proud]**. Others can spend an action to become mildly **[Enraged]** by your huge obnoxious statue of a horse man, or whatever it is. \r\n'),
('garageworks', 'GARAGEWORKS', 3, 'This is where you keep your **[Vehicles]**, boss! You care dramatically about your ride, or rides plural, and they get to have their own little respiteblock. Mwah. You can roll BUGGYBUILDERY, an alternate version of MONEYMAKERY that uses **+HUB** to earn the same amount of LUX, +1, but only for rolls to upgrade your **[Vehicle]**. Watch out though! People could theoretically steal any vehicles that you store here, if you\'re not careful! \r\n'),
('custodiancradle', 'CUSTODIANCRADLE', 3, 'You\'ve got a part of your hive dedicated to keeping your lusus content. If you have the CUSTODIAN COMPANION move, they gain an extra Feature while around the hive, and your ATRIACLIZE rolls are **[Talented]**. If they were already **[Talented]**, you get a **+2 [Buff]** to rolls with it. Trolls who break into your hive and alert security may need to fight them off as though they were a lusus; this upgrade costs **4 VP** if the lusus would be a level 2 lusus, **5 VP** if level 3 and **6 VP** if level 4. Kids— your parents are humans too! Feel free to build them a stat sheet similar to an NPC if you want them to beat up other kids invading your home, I guess.\r\n'),
('husksetup', 'HUSKSETUP', 3, 'You\'re beyond using shitty husktops to bully your friends. You\'ve got a decked out setup involving apiculture network farms, really powerful GRUs and a load of other technobabble you pretend to understand but really, really don\'t. Any **[Tech]** rolls you make at home can be **[Tiered Up]**, even to a MAX. However, beware the consequences! When you try to do this, roll 1d8. On a GOOD, GREAT or MAX result you achieved through such a **[Tier Up]**, if you roll a 1, 1-2 or 1-3 result, your HUSKSETUP overheats and melts. You\'ll need to buy a new one!\r\n'),
('grimcell', 'GRIMCELL', 3, 'Tell me what you know! This grim room is one where, once you\'re in, you know all you can do is talk. Maybe it\'s your spooky basement, maybe it\'s your interrogation room, etcetera— point is, in here, struggling is useless. You can throw someone in here with a **GREAT GRIEF** roll which does no damage. In here, no **[Physical]** or **[Strife]** rolls can be used, and the opponent can only leave if they roll an ABSCOND roll of 17+ if you lock them in. You can trap lusii in here too, if you choose.\r\n'),
('splicelab', 'SPLICELAB', 6, 'Hahaha… WEIRD SCIENCE! In this fucked up and weird lab, you can create life! Except, you know, the life is… weird. Really weird. You gain the ECTOSPLICE **[Downtime]** roll. It costs **3 LUX** to make this roll in the first place. When you want to create a creature, roll **+PSP**. \r\n\r\n> **MIN**: OOOOOH GOD OH FUCK! You create a WASTELAND HORROR, and it immediately attacks you. Good luck!\r\n\r\n> **BAD**: Agh— AGH! No bueno! You create a SPLICED monster from Chapter 19, but it is hostile to you. \r\n\r\n> **OK**: You lose your LUX. Great job, genius! \r\n\r\n> **GOOD**: Oh boy, you did it! You create a Level 1 SPLICED monster. You need to keep it somewhere, otherwise it\'ll get antsy and run away. You can use it to fight intruders in your hive instead of doing it yourself.\r\n\r\n> **GREAT**: Whoa… that\'s a super strong SPLICE! Well done! You create a Level 2 SPLICED. \r\n\r\n> **MAX**: MY WORD! What a freaky freak! But it\'s so big and strong… you create a Level 3 SPLICED!\r\n'),
('regaliarmoire', 'REGALIARMOIRE', 15, 'ALL THE ABSTRATA UPGRADES. ALL OF THEM. This armory armoire is full of ALL the weapons out there. Nobody’s gonna invade YOUR hive anymore! You gain access to every ABSTRATA UPGRADE in the game. You can swap out ABSTRATA in the middle of a fight while you’re at home, though the ABSTRATA you receive instead is randomly selected. And watch out; if someone gets away with YOINKING away an Abstrata, and you let them get away with it, you can’t use the REGALIARMOIRE until you spend **2 LUX** repairing what you’ve lost! Boohoohoo… \r\n'),
('creationsaloon', 'CREATIONSALOON', 3, 'This is where you make stuff that MATTERS. Like music. Poetry. Fursuits. You get the idea. This is a creative space for you, and everyone around you, but really it’s mostly you. Others need to get the fuck out of your hive and do art elsewhere. You take it back, it’s really only for you. Why did I say that? Stupid. Anyway, if you have a move that lets you create STUFF during **[Downtime]**, and you have this HIVECRAFTING UPGRADE, you can make an additional **[Downtime]** roll per day exclusively to do that. You can’t roll the same **[Downtime]** roll twice, though!\r\n');
INSERT INTO `monster` (`key`, `title`, `doc`, `text`) VALUES
('abominableArtist', 'ABOMINABLE ARTIST', 'TEMPLATE_NPC', 'LVL 2 NPC\r\n**12 HP**\r\nSPECIBUS: A spraypaint can flail!\r\n\r\nTALENTS: **+IMG**\r\nRAS: +1\r\nPLC: +2\r\nGRA: +0\r\nAPP: +1\r\nGRT: +0\r\nHUB: +2\r\nPSP: +0\r\nIMG: +4\r\n\r\nMOVES:\r\nART OF LIVING (Graffiti) [Abominartist]\r\nALTERNIAN GOTHIC [Abominartist]\r\nSELF PORTRAIT [Abominartist]\r\nSTARRY NIGHT [Abominartist]\r\n'),
('ambientGrimdark', 'AMBIENT GRIMDARK', 'ENTITY', 'LVL 2 ENTITY\r\n**13 HP**\r\nTALENTS: **+IMG**\r\nSTATS: **+3 IMG**\r\n\r\nThe Horrorterrors’ attention is not a gift easily acquired, and as those who receive it inevitably find, it’s not easily relinquished either. Some signed-away souls are of more use to them sticking around than fading away, even in death - and it’s not much work at all for them to add another category to Alternia’s various kinds of unlife. The Ambient Grimdark, a soul given form by the void. While it may resemble a ghost, it’s really just a shadow puppet in the shape of one... and while some can manage to keep their sense of self intact despite everything, this one clearly hasn’t.\r\n\r\nMOVES: \r\n> DEAL GONE WRONG\r\n> DARKER MAGICKS\r\n> LOST SOUL'),
('anOrdinaryCluckbeast', 'AN ORDINARY CLUCKBEAST', 'ENTITY', 'LVL 4 ENTITY\r\n**10 HP**\r\nTALENTS: **+++STRIFE**\r\nSTATS: **+5 ALL** but only when used for **[Strife]**, otherwise 0\r\nThis is an ordinary cluckbeast! It has a beak, and scratchy chicken feets, and fluffy speckled white feathers, and it goes cockadoodle doo. Its nest is surrounded by bones! Where did you get those bones from, Ms. Chicken?  \r\n\r\nMOVES: \r\n> OH GOD OH GOD OH GOD OH GOD\r\n> HOLD SHIT IT\'S SO FAST\r\n> WHERE DID IT GO?!\r\n> I WANT MY LUSUS\r\n> THE GODS HAVE TURNED THEIR EYES FROM THIS CREATURE'),
('axon', 'AXON', 'ENTITY', 'LVL 3 ENTITY\r\n**18 HP**\r\nTALENTS: **++IMG**\r\nSTATS: **+2 IMG, +2 GRA, -1 PSP** \r\nWhenever a powerful Goldblood perishes in an emotionally charged state, its psionics may continue to tie its wandering spirit to the mortal plane. These jittery balls of crackling energy are known as Axon, and tend to gather in large numbers, causing unnatural psionic thunderstorms. \r\n\r\nMOVES: \r\n> ELECTRIC MIND\r\n> DENDRITE\r\n> BRAINSTORM\r\n> BRAINBUSTER\r\n'),
('barkfiend', 'BARKFIEND', 'LUSUS', 'LVL 1 LUSUS\r\n**8 HP**\r\nTALENTS: **+GRT, +HUB**\r\nSTATS: **+3 GRT, +2 HUB, +2 PSP**\r\nThis wolflike creature has two sets of fanged mouths built into its snout; one for huffing and puffing, one for howling, and both for laying waste into people who would get in their way.\r\n\r\nMOVES: \r\n> AROOOOOO\r\n> HUFF PUFF\r\n> HELLFANGS\r\n> SNIFFLES'),
('batteryBeehemoth', 'BATTERY-BEEHEMOTH', 'LUSUS', 'LVL 3 LUSUS\r\n**16 HP**\r\nTALENTS: **++IMG, +HUB**\r\nSTATS: **+2 IMG, +2 HUB** \r\nEvery store in the gold districts is filled with batterybugs, cute cubey caterpillar-looking things that can be used to siphon excess psionic energy off Battery golds. Leave a batterybug on your head too long, though, and it might just suck every ounce of energy out of your body and molt into a BATTERY-BEEHEMOTH, a two-headed, four-eyed glow-in-the-dark wasp monster powered by gamer energy and gamer rage. \r\n\r\nMOVES: \r\n> GAMER MURDER SPEEDRUN ANY%\r\n> SUPERDUPERCHARGED\r\n> GAMERS HAVE A BOND\r\n> CAUTERIZE\r\n> MONSTER ENERGY SUPER ULTRA DEATH EXPLOSION'),
('bigDamnHero', 'BIG DAMN HERO', 'TEMPLATE_NPC', 'LVL 2 NPC\r\n**12 HP**\r\nSPECIBUS: Hammer of Heroes!\r\n\r\nTALENTS: **+IMG**\r\nRAS: +0\r\nPLC: +1\r\nGRA: +2\r\nAPP: +0\r\nGRT: +0\r\nHUB: +1\r\nPSP: +2\r\nIMG: +4\r\n\r\nMOVES:\r\nSUPERCHARGED [Gold]\r\nWITH GREAT POWER (Hero) [Superscoundrel]\r\nPOWER UP (Energy Blast) [Superscoundrel]\r\nBEHOLD! [Superscoundrel]\r\n'),
('bitchInBlue', 'BITCH IN BLUE', 'TEMPLATE_NPC', 'LVL 2 NPC\r\n**16 HP**\r\nSPECIBUS: A standard issue pistol, telescopic baton, or flip knife\r\n\r\nTALENTS: **+GRT**\r\nRAS: +0\r\nPLC: +2\r\nGRA: +1\r\nAPP: +0\r\nGRT: +4\r\nHUB: +2\r\nPSP: +1\r\nIMG: +0\r\n\r\nMOVES:\r\nHERESY ERADICATION TASKFORCE [HET]\r\nIMPERIAL DICTATION [HET]\r\nMADE MAN MAKER [HET]\r\nLIGHTS, CAMERA, DRONESTRIKE! [HET]\r\n'),
('bleatank', 'BLEATANK', 'LUSUS', 'LVL 1 LUSUS\r\n**6 HP**\r\nTALENTS: **+PLC, +IMG**\r\nSTATS: **+2 RAS, +2 PLC, +2 IMG**\r\nIt\'s a goat. Or a sheep? It could be either, really, but it\'s definitely unhappy with you. These usually-burgundy lusii have psionic abilities not unlike their charges, as well as some serious FLOOFAGE.\r\n\r\nMOVES: \r\n> BAABAABLAST\r\n> WOOLOO...Y\r\n> MESS WITH THE RAM\r\n> FWOOF'),
('bomp', 'B.O.M.P.', 'LUSUS ', 'LVL 0 LUSUS\r\n**1 HP**\r\nTALENTS: **+HUB, -GRT**\r\nSTATS: -1 ALL\r\n\r\nThe Beast of Microscopic Proportions, or BOMP for short, is a harmless lusus entirely beneath your notice. It flits around your ears, buzzes annoyingly loudly despite not being visible to the naked eye, and… well, that’s about it. It doesn’t even bite. It’s not worth the effort to swat, and is even *less* worth trying to find and capture. Some creatures are simply meant to fly wild and buzz annoyingly in your ears… and those who gaze upon the BOMP’s microscopic proportions are likely to regret the experience.\r\n\r\nMOVES:\r\n> TINY FUCKER\r\n> CHORUS OF THE CEASELESS BUZZING\r\n> OBSERVING WHAT SHOULD NOT BE SEEN\r\n> BLINK AND YOU MISS IT'),
('bronzeBiter', 'BRONZE BITER', 'TEMPLATE_NPC', 'LVL 2 NPC\r\n**16 HP**\r\nSPECIBUS: BIG MEATY CLAWS AND SCARILY SHARP JAWS\r\n\r\nTALENTS: **+GRT**\r\nRAS: +2\r\nPLC: +0\r\nGRA: +1\r\nAPP: +2\r\nGRT: +4\r\nHUB: +1\r\nPSP: +0\r\nIMG: +0\r\n\r\nMOVES:\r\nGRR BARK BARK BARK [Moonbark]\r\nEVISCERATE [Moonbark]\r\nHUNTER’S SENSES [Moonbark]\r\nBARKING MAD [Moonbark]\r\n'),
('bronzeStoryteller', 'BRONZE STORYTELLER', 'CASTE_NPC', 'LVL 1 NPC\r\n**8 HP**\r\nSPECIBUS: A really heavy book, old machete, or cleaver\r\n\r\nTALENTS: **+PLC**\r\nRAS: +1\r\nPLC: +3\r\nGRA: +2\r\nAPP: +0\r\nGRT: +0\r\nHUB: +0\r\nPSP: +2\r\nIMG: +1\r\n\r\nMOVES:\r\nYARNCHASER (Faeries & Magic) [Bronze]\r\nGIFT OF THE GAB [Bronze]\r\nCHRONIC WORRY-WART [Bronze]\r\n'),
